use std::collections::HashSet;
use std::thread;
use std::time::Duration;

use crate::agent::tools::ToolResult;

pub use crate::agent::adapters::acp_client::{
    AcpAgentMetadata, AcpClientError, AcpRunStatus, AcpTransport, ReqwestAcpTransport,
    normalize_endpoint,
};

const ACP_POLL_INTERVAL: Duration = Duration::from_millis(25);

#[derive(Debug, Clone, PartialEq)]
pub struct DiscoveredAcpAgent {
    pub endpoint: String,
    pub metadata: AcpAgentMetadata,
}

#[derive(Debug, Default)]
pub struct AcpDiscoveryReport {
    pub agents: Vec<DiscoveredAcpAgent>,
    pub errors: Vec<AcpClientError>,
}

#[derive(Debug, Clone)]
pub struct AcpDiscovery<T = ReqwestAcpTransport> {
    endpoints: Vec<String>,
    transport: T,
}

impl<T> AcpDiscovery<T> {
    pub fn new(endpoints: Vec<String>, transport: T) -> Self {
        Self {
            endpoints,
            transport,
        }
    }
}

impl<T> AcpDiscovery<T>
where
    T: AcpTransport,
{
    pub fn discover(&self, existing: &HashSet<(String, String)>) -> AcpDiscoveryReport {
        let mut report = AcpDiscoveryReport::default();
        let mut seen = existing.clone();

        for endpoint in &self.endpoints {
            match self.transport.list_agents(endpoint) {
                Ok(agents) => {
                    for metadata in agents {
                        let key = (normalize_endpoint(endpoint), metadata.id.clone());
                        if seen.insert(key) {
                            report.agents.push(DiscoveredAcpAgent {
                                endpoint: normalize_endpoint(endpoint),
                                metadata,
                            });
                        }
                    }
                }
                Err(error) => report.errors.push(error),
            }
        }

        report
    }
}

pub fn poll_run_to_completion<T: AcpTransport>(
    transport: &T,
    endpoint: &str,
    run_id: &str,
    max_polls: usize,
) -> Result<ToolResult, AcpClientError> {
    for _ in 0..max_polls {
        match transport.get_run(endpoint, run_id)? {
            AcpRunStatus::Pending => thread::sleep(ACP_POLL_INTERVAL),
            AcpRunStatus::Complete(result) => return Ok(result),
        }
    }

    Ok(ToolResult::failure(format!(
        "ACP run {run_id} timed out after {max_polls} polls"
    )))
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::agent::adapters::acp_client::{AcpAgentMetadata, AcpClientError, AcpRunStatus};
    use crate::agent::tools::ToolResult;
    use serde_json::Value;

    #[derive(Clone)]
    struct FakeTransport;

    impl AcpTransport for FakeTransport {
        fn get_agent(
            &self,
            _endpoint: &str,
            _agent_id: &str,
        ) -> Result<AcpAgentMetadata, AcpClientError> {
            unimplemented!()
        }

        fn list_agents(&self, _endpoint: &str) -> Result<Vec<AcpAgentMetadata>, AcpClientError> {
            Ok(vec![])
        }

        fn create_run(
            &self,
            _endpoint: &str,
            _agent_id: &str,
            _input: &Value,
        ) -> Result<String, AcpClientError> {
            unimplemented!()
        }

        fn get_run(&self, _endpoint: &str, _run_id: &str) -> Result<AcpRunStatus, AcpClientError> {
            // Always returns Pending so the poll loop exhausts max_polls.
            Ok(AcpRunStatus::Pending)
        }
    }

    #[test]
    fn poll_run_to_completion_returns_timeout_after_max_polls() {
        let transport = FakeTransport;
        let result = poll_run_to_completion(&transport, "http://example.com", "run-1", 3)
            .expect("should not return Err");

        assert!(result.is_error);
        assert!(
            result.text_output().contains("timed out"),
            "expected timeout message, got: {}",
            result.text_output()
        );
    }

    #[test]
    fn poll_run_to_completion_returns_result_after_pending_polls() {
        // Transport that returns Pending twice then Complete.
        #[derive(Clone)]
        struct PendThenComplete {
            calls: std::sync::Arc<std::sync::atomic::AtomicUsize>,
        }

        impl AcpTransport for PendThenComplete {
            fn get_agent(&self, _: &str, _: &str) -> Result<AcpAgentMetadata, AcpClientError> {
                unimplemented!()
            }
            fn list_agents(&self, _: &str) -> Result<Vec<AcpAgentMetadata>, AcpClientError> {
                Ok(vec![])
            }
            fn create_run(&self, _: &str, _: &str, _: &Value) -> Result<String, AcpClientError> {
                unimplemented!()
            }
            fn get_run(&self, _: &str, _: &str) -> Result<AcpRunStatus, AcpClientError> {
                let n = self.calls.fetch_add(1, std::sync::atomic::Ordering::SeqCst);
                if n < 2 {
                    Ok(AcpRunStatus::Pending)
                } else {
                    Ok(AcpRunStatus::Complete(ToolResult::success("done")))
                }
            }
        }

        let transport = PendThenComplete {
            calls: std::sync::Arc::new(std::sync::atomic::AtomicUsize::new(0)),
        };
        let result = poll_run_to_completion(&transport, "http://example.com", "run-2", 10)
            .expect("should succeed");

        assert!(!result.is_error);
        assert_eq!(result.text_output(), "done");
    }
}

use serde::Deserialize;
use serde_json::Value;

use crate::agent::tools::{ContentPart, ToolResult};

#[derive(Debug, Clone, PartialEq)]
pub struct AcpAgentMetadata {
    pub id: String,
    pub name: String,
    pub description: String,
    pub input_schema: Value,
}

#[derive(Debug, Clone, PartialEq)]
pub enum AcpRunStatus {
    Pending,
    Complete(ToolResult),
}

pub(super) fn parse_agent_metadata(value: &Value) -> Result<AcpAgentMetadata, String> {
    let wire: AgentMetadataWire =
        serde_json::from_value(value.clone()).map_err(|error| error.to_string())?;
    if wire.id.trim().is_empty() {
        return Err("agent id must not be empty".into());
    }
    let name = wire
        .name
        .map(|name| name.trim().to_string())
        .filter(|name| !name.is_empty())
        .unwrap_or_else(|| wire.id.clone());
    Ok(AcpAgentMetadata {
        id: wire.id,
        name,
        description: wire.description.unwrap_or_default(),
        input_schema: wire
            .input_schema
            .unwrap_or_else(|| serde_json::json!({"type": "object"})),
    })
}

pub(super) fn parse_run_status(value: &Value) -> Result<AcpRunStatus, String> {
    let status = value
        .get("status")
        .and_then(Value::as_str)
        .ok_or_else(|| "run status must be a string".to_string())?;

    match status {
        "queued" | "running" | "pending" | "in_progress" => Ok(AcpRunStatus::Pending),
        "completed" | "succeeded" => {
            let output_value = value
                .get("output")
                .or_else(|| value.get("result"))
                .ok_or_else(|| format!("run with status '{status}' must contain output"))?;
            parse_tool_result(output_value, false).map(AcpRunStatus::Complete)
        }
        "failed" | "cancelled" | "canceled" => {
            if let Some(output_value) = value.get("output").or_else(|| value.get("result")) {
                parse_tool_result(output_value, true).map(AcpRunStatus::Complete)
            } else {
                Ok(AcpRunStatus::Complete(ToolResult::failure(format!(
                    "ACP run ended with status '{status}'"
                ))))
            }
        }
        other => Err(format!("unknown ACP run status '{other}'")),
    }
}

fn parse_tool_result(value: &Value, default_is_error: bool) -> Result<ToolResult, String> {
    let is_error = value
        .get("is_error")
        .or_else(|| value.get("isError"))
        .and_then(Value::as_bool)
        .unwrap_or(default_is_error)
        || default_is_error;
    let output_truncated = value
        .get("output_truncated")
        .or_else(|| value.get("outputTruncated"))
        .and_then(Value::as_bool)
        .unwrap_or(false);
    let exit_code = value
        .get("exit_code")
        .or_else(|| value.get("exitCode"))
        .and_then(Value::as_i64)
        .map(|code| i32::try_from(code).map_err(|_| "exit code must fit within i32".to_string()))
        .transpose()?;

    let content = if let Some(content) = value.get("content") {
        parse_content_parts(content)?
    } else if let Some(text) = value.get("text").and_then(Value::as_str) {
        vec![ContentPart::text(text)]
    } else {
        return Err("tool output must contain content or text".into());
    };

    Ok(ToolResult {
        content,
        exit_code,
        is_error,
        output_truncated,
    })
}

fn parse_content_parts(value: &Value) -> Result<Vec<ContentPart>, String> {
    let Some(entries) = value.as_array() else {
        return Err("content must be an array".into());
    };

    let mut parts = Vec::with_capacity(entries.len());
    for entry in entries {
        let kind = entry.get("type").and_then(Value::as_str).unwrap_or("text");
        match kind {
            "text" => {
                let text = entry
                    .get("text")
                    .and_then(Value::as_str)
                    .ok_or_else(|| "text content entry must contain text".to_string())?;
                parts.push(ContentPart::text(text));
            }
            "resource" => {
                let uri = entry
                    .get("uri")
                    .and_then(Value::as_str)
                    .ok_or_else(|| "resource content entry must contain uri".to_string())?;
                let mime_type = entry
                    .get("mime_type")
                    .or_else(|| entry.get("mimeType"))
                    .and_then(Value::as_str)
                    .map(ToOwned::to_owned);
                parts.push(ContentPart::Resource {
                    uri: uri.to_string(),
                    mime_type,
                });
            }
            other => return Err(format!("unsupported ACP content part type: {other}")),
        }
    }

    Ok(parts)
}

#[derive(Debug, Deserialize)]
struct AgentMetadataWire {
    id: String,
    name: Option<String>,
    description: Option<String>,
    #[serde(default, alias = "inputSchema")]
    input_schema: Option<Value>,
}

#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::json;

    #[test]
    fn parse_agent_metadata_falls_back_to_id_for_blank_name() {
        let metadata = parse_agent_metadata(&json!({
            "id": "reviewer",
            "name": "   ",
            "description": "Reviews code"
        }))
        .expect("metadata should parse");

        assert_eq!(metadata.name, "reviewer");
    }

    #[test]
    fn parse_run_status_rejects_exit_code_overflow() {
        let error = parse_run_status(&json!({
            "status": "completed",
            "output": {
                "content": [{ "type": "text", "text": "done" }],
                "exit_code": i64::from(i32::MAX) + 1
            }
        }))
        .expect_err("overflowing exit code should fail");

        assert!(error.contains("exit code must fit within i32"));
    }

    #[test]
    fn parse_agent_metadata_rejects_empty_id() {
        // Line 24: empty id returns Err.
        let err = parse_agent_metadata(&json!({
            "id": "   ",
            "name": "agent"
        }))
        .expect_err("empty id should fail");
        assert!(err.contains("agent id must not be empty"));
    }

    #[test]
    fn parse_run_status_failed_without_output_generates_message() {
        // Lines 60-61: failed/cancelled status with no output field.
        let status = parse_run_status(&json!({
            "status": "cancelled"
        }))
        .expect("cancelled without output should parse");
        let AcpRunStatus::Complete(result) = status else {
            panic!("should be complete");
        };
        assert!(result.is_error);
        assert!(result.text_output().contains("cancelled"));
    }

    #[test]
    fn parse_tool_result_missing_content_and_text_errors() {
        // Line 93: output without content or text.
        let err = parse_run_status(&json!({
            "status": "completed",
            "output": { "exit_code": 0 }
        }))
        .expect_err("missing content/text should fail");
        assert!(err.contains("must contain content or text"));
    }

    #[test]
    fn parse_content_parts_rejects_non_array_content() {
        // Line 106: content is not an array.
        let err = parse_run_status(&json!({
            "status": "completed",
            "output": { "content": "not-an-array" }
        }))
        .expect_err("non-array content should fail");
        assert!(err.contains("content must be an array"));
    }

    #[test]
    fn parse_content_parts_rejects_unsupported_type() {
        // Line 135: unsupported content part type.
        let err = parse_run_status(&json!({
            "status": "completed",
            "output": {
                "content": [{ "type": "image", "url": "http://example.com" }]
            }
        }))
        .expect_err("unsupported type should fail");
        assert!(err.contains("unsupported ACP content part type: image"));
    }

    #[test]
    fn parse_run_status_rejects_unknown_status_values() {
        let error = parse_run_status(&json!({
            "status": "mystery-state"
        }))
        .expect_err("unknown statuses should be rejected explicitly");

        assert!(error.contains("mystery-state"));
    }

    #[test]
    fn parse_run_status_marks_failed_output_as_error_when_field_missing() {
        let status = parse_run_status(&json!({
            "status": "failed",
            "output": {
                "content": [{ "type": "text", "text": "validation failed" }]
            }
        }))
        .expect("failed payload should parse");

        let AcpRunStatus::Complete(result) = status else {
            panic!("failed runs should be terminal");
        };
        assert!(result.is_error);
        assert_eq!(result.text_output(), "validation failed");
    }

    #[test]
    fn parse_run_status_keeps_cancelled_output_marked_as_error_when_false() {
        let status = parse_run_status(&json!({
            "status": "cancelled",
            "output": {
                "content": [{ "type": "text", "text": "cancelled by user" }],
                "is_error": false
            }
        }))
        .expect("cancelled payload should parse");

        let AcpRunStatus::Complete(result) = status else {
            panic!("cancelled runs should be terminal");
        };
        assert!(result.is_error);
        assert_eq!(result.text_output(), "cancelled by user");
    }
}

mod client;
mod mapper;

use serde_json::json;

use super::conformance::AgentAdapterContractProbe;
use mapper::{parse_agent_metadata, parse_run_status};

pub use client::{AcpClientError, AcpTransport, ReqwestAcpTransport, normalize_endpoint};
pub use mapper::{AcpAgentMetadata, AcpRunStatus};

#[derive(Debug, Default, Clone, Copy)]
pub struct AcpAdapterContractProbe {
    _private: (),
}

impl AgentAdapterContractProbe for AcpAdapterContractProbe {
    fn fetch_agent(&self) -> Result<(), String> {
        parse_agent_metadata(&json!({
            "id": "reviewer",
            "name": "ACP Reviewer",
            "description": "Reviews code",
            "input_schema": { "type": "object" }
        }))
        .map(|_| ())
    }

    fn create_run(&self) -> Result<(), String> {
        let payload = json!({ "id": "run-123" });
        payload
            .get("id")
            .or_else(|| payload.get("run_id"))
            .and_then(serde_json::Value::as_str)
            .map(|_| ())
            .ok_or_else(|| "response must contain run id".to_string())
    }

    fn poll_terminal(&self) -> Result<(), String> {
        match parse_run_status(&json!({
            "status": "completed",
            "output": { "text": "done" }
        }))? {
            AcpRunStatus::Pending => Err("completed status must map to terminal result".into()),
            AcpRunStatus::Complete(_) => Ok(()),
        }
    }
}

pub trait AgentAdapterContractProbe {
    fn fetch_agent(&self) -> Result<(), String>;
    fn create_run(&self) -> Result<(), String>;
    fn poll_terminal(&self) -> Result<(), String>;
}

#[derive(Debug, Default, Clone, PartialEq, Eq)]
pub struct ConformanceReport {
    pub failures: Vec<String>,
}

impl ConformanceReport {
    pub fn all_passed(&self) -> bool {
        self.failures.is_empty()
    }
}

pub fn run_adapter_conformance_suite<P: AgentAdapterContractProbe>(probe: P) -> ConformanceReport {
    let mut failures = Vec::new();
    if let Err(err) = probe.fetch_agent() {
        failures.push(format!("fetch_agent: {err}"));
        return ConformanceReport { failures };
    }
    if let Err(err) = probe.create_run() {
        failures.push(format!("create_run: {err}"));
        return ConformanceReport { failures };
    }
    if let Err(err) = probe.poll_terminal() {
        failures.push(format!("poll_terminal: {err}"));
    }
    ConformanceReport { failures }
}

