use crate::agent::capability::{
    CapabilityClaim, CapabilityHandle, CapabilityInput, CapabilityResult,
};
use crate::agent::tools::Tool;

pub struct AcpToolCapability<'a> {
    tool: &'a dyn Tool,
}

impl<'a> AcpToolCapability<'a> {
    pub fn from_tool(tool: &'a dyn Tool) -> Self {
        Self { tool }
    }

    pub fn handle(&self) -> CapabilityHandle {
        CapabilityHandle::new(self.tool.spec().name, self.tool.kind().into())
    }

    pub fn claims(&self, input: &CapabilityInput) -> Vec<CapabilityClaim> {
        self.tool
            .resource_claims(&input.arguments)
            .into_iter()
            .map(Into::into)
            .collect()
    }

    pub fn execute(&self, input: CapabilityInput) -> CapabilityResult {
        self.tool.execute(input.arguments).into()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::agent::capability::{CapabilityAccess, CapabilityContentPart, CapabilityKind};
    use crate::agent::tools::{ResourceAccess, ResourceClaim, ToolKind, ToolResult, ToolSpec};
    use serde_json::{Value, json};

    struct FakeAcpTool;

    impl crate::agent::tools::Tool for FakeAcpTool {
        fn spec(&self) -> ToolSpec {
            ToolSpec {
                name: "acp-probe".into(),
                description: "fake acp tool".into(),
                parameters: json!({
                    "type": "object",
                    "properties": {},
                    "additionalProperties": false
                }),
            }
        }

        fn kind(&self) -> ToolKind {
            ToolKind::Agent { is_acp: true }
        }

        fn resource_claims(&self, args: &Value) -> Vec<ResourceClaim> {
            if args.get("workspace_lock").and_then(Value::as_bool) == Some(true) {
                vec![ResourceClaim {
                    resource: "fs:workspace.lock".into(),
                    access: ResourceAccess::ReadWrite,
                }]
            } else {
                Vec::new()
            }
        }

        fn execute(&self, _args: Value) -> ToolResult {
            ToolResult::success("acp-ok")
        }
    }

    #[test]
    fn acp_wrapper_exposes_handle_claims_and_result_via_capability_contracts() {
        let wrapper = AcpToolCapability::from_tool(&FakeAcpTool);
        let input = CapabilityInput::new(json!({"workspace_lock": true}));

        assert_eq!(
            wrapper.handle(),
            CapabilityHandle {
                name: "acp-probe".into(),
                kind: CapabilityKind::Agent { is_acp: true },
            }
        );
        assert_eq!(
            wrapper.claims(&input),
            vec![CapabilityClaim {
                resource: "fs:workspace.lock".into(),
                access: CapabilityAccess::ReadWrite,
            }]
        );

        let result = wrapper.execute(input);
        assert_eq!(
            result.content,
            vec![CapabilityContentPart::Text {
                text: "acp-ok".into(),
            }]
        );
    }
}

use crate::agent::capability::{
    CapabilityClaim, CapabilityHandle, CapabilityInput, CapabilityKind, CapabilityResult,
};
use crate::agent::tools::{ResourceClaim, Tool};

pub struct LocalToolCapability<'a> {
    tool: &'a dyn Tool,
}

impl<'a> LocalToolCapability<'a> {
    pub fn from_tool(tool: &'a dyn Tool) -> Self {
        Self { tool }
    }

    pub fn kind(&self) -> CapabilityKind {
        self.tool.kind().into()
    }

    pub fn handle(&self) -> CapabilityHandle {
        CapabilityHandle::new(self.tool.spec().name, self.kind())
    }

    pub fn claims(&self, input: &CapabilityInput) -> Vec<CapabilityClaim> {
        self.tool
            .resource_claims(&input.arguments)
            .into_iter()
            .map(Into::into)
            .collect()
    }

    pub fn resource_claims(&self, input: &CapabilityInput) -> Vec<ResourceClaim> {
        self.claims(input).into_iter().map(Into::into).collect()
    }

    pub fn execute(&self, input: CapabilityInput) -> CapabilityResult {
        self.tool.execute(input.arguments).into()
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::agent::capability::{CapabilityAccess, CapabilityContentPart, ConflictPolicy};
    use crate::agent::tools::{ResourceAccess, ToolResult, ToolSpec};
    use serde_json::{Value, json};

    struct FakeLocalTool;

    impl Tool for FakeLocalTool {
        fn spec(&self) -> ToolSpec {
            ToolSpec {
                name: "fake".into(),
                description: "fake local tool".into(),
                parameters: json!({
                    "type": "object",
                    "properties": {},
                    "additionalProperties": false
                }),
            }
        }

        fn resource_claims(&self, args: &Value) -> Vec<ResourceClaim> {
            args.get("path")
                .and_then(Value::as_str)
                .map(|path| {
                    vec![ResourceClaim {
                        resource: format!("fs:{path}"),
                        access: ResourceAccess::ReadWrite,
                    }]
                })
                .unwrap_or_default()
        }

        fn execute(&self, args: Value) -> ToolResult {
            let text = args
                .get("text")
                .and_then(Value::as_str)
                .unwrap_or_default()
                .to_string();
            ToolResult::success(text)
        }
    }

    #[test]
    fn local_wrapper_projects_claims_and_results_to_capability_contracts() {
        let wrapper = LocalToolCapability::from_tool(&FakeLocalTool);
        let input = CapabilityInput::new(json!({"path":"src/main.rs", "text":"done"}));

        assert_eq!(
            wrapper.handle(),
            CapabilityHandle {
                name: "fake".into(),
                kind: CapabilityKind::Local,
            }
        );

        assert_eq!(wrapper.kind(), CapabilityKind::Local);
        assert_eq!(
            wrapper.claims(&input),
            vec![CapabilityClaim {
                resource: "fs:src/main.rs".into(),
                access: CapabilityAccess::ReadWrite,
            }]
        );

        let result = wrapper.execute(input);
        assert!(!result.is_error);
        assert_eq!(
            result.content,
            vec![CapabilityContentPart::Text {
                text: "done".into()
            }]
        );
    }

    #[test]
    fn local_wrapper_claims_keep_conflict_policy_semantics() {
        let wrapper = LocalToolCapability::from_tool(&FakeLocalTool);
        let write_claims = wrapper.claims(&CapabilityInput::new(json!({"path":"src/main.rs"})));
        let other_write_claims =
            wrapper.claims(&CapabilityInput::new(json!({"path":"src/main.rs"})));

        assert_eq!(
            ConflictPolicy::from_claims(&write_claims, &other_write_claims),
            ConflictPolicy::Conflicting
        );
    }
}

pub mod acp;
pub mod local;
mod types;

pub use acp::AcpToolCapability;
pub use local::LocalToolCapability;
pub use types::{
    CapabilityAccess, CapabilityClaim, CapabilityContentPart, CapabilityError, CapabilityHandle,
    CapabilityInput, CapabilityKind, CapabilityResult, ConflictPolicy,
};

use serde_json::Value;
use std::error::Error;
use std::fmt::{Display, Formatter};

#[derive(Debug, Clone, PartialEq)]
pub struct CapabilityInput {
    pub arguments: Value,
}

impl CapabilityInput {
    pub fn new(arguments: Value) -> Self {
        Self { arguments }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum CapabilityKind {
    Local,
    Agent { is_acp: bool },
}

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct CapabilityHandle {
    pub name: String,
    pub kind: CapabilityKind,
}

impl CapabilityHandle {
    pub fn new(name: impl Into<String>, kind: CapabilityKind) -> Self {
        Self {
            name: name.into(),
            kind,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum CapabilityAccess {
    ReadOnly,
    ReadWrite,
    Exclusive,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct CapabilityClaim {
    pub resource: String,
    pub access: CapabilityAccess,
}

impl CapabilityClaim {
    pub fn conflict_policy_with(&self, other: &Self) -> ConflictPolicy {
        ConflictPolicy::from_claims(std::slice::from_ref(self), std::slice::from_ref(other))
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ConflictPolicy {
    Compatible,
    Conflicting,
}

impl ConflictPolicy {
    pub fn is_conflicting(self) -> bool {
        matches!(self, Self::Conflicting)
    }

    pub fn from_claims(left: &[CapabilityClaim], right: &[CapabilityClaim]) -> Self {
        if has_exclusive_claim(left) || has_exclusive_claim(right) {
            return Self::Conflicting;
        }

        if left.iter().any(|left_claim| {
            right.iter().any(|right_claim| {
                left_claim.resource == right_claim.resource
                    && !matches!(
                        (left_claim.access, right_claim.access),
                        (CapabilityAccess::ReadOnly, CapabilityAccess::ReadOnly)
                    )
            })
        }) {
            return Self::Conflicting;
        }

        Self::Compatible
    }
}

fn has_exclusive_claim(claims: &[CapabilityClaim]) -> bool {
    claims
        .iter()
        .any(|claim| matches!(claim.access, CapabilityAccess::Exclusive))
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct CapabilityError {
    pub message: String,
    pub code: Option<String>,
}

impl CapabilityError {
    pub fn new(message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
            code: None,
        }
    }

    pub fn with_code(code: impl Into<String>, message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
            code: Some(code.into()),
        }
    }
}

impl Display for CapabilityError {
    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        match &self.code {
            Some(code) => write!(f, "{code}: {}", self.message),
            None => f.write_str(&self.message),
        }
    }
}

impl Error for CapabilityError {}

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum CapabilityContentPart {
    Text {
        text: String,
    },
    Resource {
        uri: String,
        mime_type: Option<String>,
    },
}

impl CapabilityContentPart {
    pub fn text(text: impl Into<String>) -> Self {
        Self::Text { text: text.into() }
    }

    fn text_projection(&self) -> String {
        match self {
            Self::Text { text } => text.clone(),
            Self::Resource { uri, mime_type } => match mime_type {
                Some(mime_type) => format!("[resource] {uri} ({mime_type})"),
                None => format!("[resource] {uri}"),
            },
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct CapabilityResult {
    pub content: Vec<CapabilityContentPart>,
    pub exit_code: Option<i32>,
    pub is_error: bool,
    pub output_truncated: bool,
    pub error: Option<CapabilityError>,
}

impl CapabilityResult {
    pub fn success(output: impl Into<String>) -> Self {
        Self {
            content: vec![CapabilityContentPart::text(output)],
            exit_code: None,
            is_error: false,
            output_truncated: false,
            error: None,
        }
    }

    pub fn failure(output: impl Into<String>) -> Self {
        let message = output.into();
        Self {
            content: vec![CapabilityContentPart::text(message.clone())],
            exit_code: None,
            is_error: true,
            output_truncated: false,
            error: Some(CapabilityError::new(message)),
        }
    }

    pub fn from_error(error: CapabilityError) -> Self {
        let message = error.message.clone();
        Self {
            content: vec![CapabilityContentPart::text(message)],
            exit_code: None,
            is_error: true,
            output_truncated: false,
            error: Some(error),
        }
    }

    pub fn text_output(&self) -> String {
        // Keep this projection behavior in lockstep with ToolResult::text_output and
        // conversion bridges so mixed text/resource rendering stays behavior-stable.
        let mut output = String::new();
        let mut previous_was_resource = false;
        for part in &self.content {
            match part {
                CapabilityContentPart::Text { text } => {
                    if previous_was_resource && !output.ends_with('\n') && !text.starts_with('\n') {
                        output.push('\n');
                    }
                    output.push_str(text);
                    previous_was_resource = false;
                }
                CapabilityContentPart::Resource { .. } => {
                    if !output.is_empty() && !output.ends_with('\n') {
                        output.push('\n');
                    }
                    output.push_str(&part.text_projection());
                    previous_was_resource = true;
                }
            }
        }
        if output.is_empty()
            && let Some(error) = &self.error
        {
            output.push_str(&error.message);
        }
        output
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn capability_result_helpers_build_expected_flags() {
        let ok = CapabilityResult::success("done");
        assert_eq!(
            ok.content,
            vec![CapabilityContentPart::Text {
                text: "done".into()
            }]
        );
        assert_eq!(ok.text_output(), "done");
        assert!(!ok.is_error);
        assert_eq!(ok.exit_code, None);
        assert_eq!(ok.error, None);

        let err = CapabilityResult::failure("nope");
        assert_eq!(
            err.content,
            vec![CapabilityContentPart::Text {
                text: "nope".into()
            }]
        );
        assert_eq!(err.text_output(), "nope");
        assert!(err.is_error);
        assert!(!err.output_truncated);
        assert_eq!(err.error, Some(CapabilityError::new("nope")));
    }

    #[test]
    fn capability_result_text_output_summarizes_resource_content_parts() {
        let result = CapabilityResult {
            content: vec![CapabilityContentPart::Resource {
                uri: "file://workspace/out.txt".into(),
                mime_type: Some("text/plain".into()),
            }],
            exit_code: None,
            is_error: false,
            output_truncated: false,
            error: None,
        };

        assert_eq!(
            result.text_output(),
            "[resource] file://workspace/out.txt (text/plain)"
        );
    }

    #[test]
    fn conflict_policy_matches_scheduler_rules() {
        let read_claim = CapabilityClaim {
            resource: "fs:src/main.rs".into(),
            access: CapabilityAccess::ReadOnly,
        };
        let write_claim = CapabilityClaim {
            resource: "fs:src/main.rs".into(),
            access: CapabilityAccess::ReadWrite,
        };
        let exclusive_claim = CapabilityClaim {
            resource: "process:bash".into(),
            access: CapabilityAccess::Exclusive,
        };
        let other_read_claim = CapabilityClaim {
            resource: "fs:src/lib.rs".into(),
            access: CapabilityAccess::ReadOnly,
        };

        assert_eq!(
            ConflictPolicy::from_claims(
                std::slice::from_ref(&read_claim),
                std::slice::from_ref(&read_claim)
            ),
            ConflictPolicy::Compatible
        );
        assert_eq!(
            ConflictPolicy::from_claims(std::slice::from_ref(&read_claim), &[write_claim]),
            ConflictPolicy::Conflicting
        );
        assert_eq!(
            ConflictPolicy::from_claims(
                std::slice::from_ref(&other_read_claim),
                std::slice::from_ref(&exclusive_claim)
            ),
            ConflictPolicy::Conflicting
        );
        assert_eq!(
            read_claim.conflict_policy_with(&other_read_claim),
            ConflictPolicy::Compatible
        );
    }

    #[test]
    fn capability_error_display_includes_optional_code() {
        let plain = CapabilityError::new("boom");
        assert_eq!(plain.to_string(), "boom");

        let coded = CapabilityError::with_code("ACP_TIMEOUT", "timed out");
        assert_eq!(coded.to_string(), "ACP_TIMEOUT: timed out");
    }

    #[test]
    fn capability_handle_captures_identity_and_kind() {
        let handle = CapabilityHandle::new("read_file", CapabilityKind::Local);
        assert_eq!(
            handle,
            CapabilityHandle {
                name: "read_file".into(),
                kind: CapabilityKind::Local,
            }
        );
    }

    #[test]
    fn capability_text_output_falls_back_to_error_message_for_metadata_only_failures() {
        let result = CapabilityResult {
            content: Vec::new(),
            exit_code: None,
            is_error: false,
            output_truncated: false,
            error: Some(CapabilityError::with_code("ACP_TIMEOUT", "timed out")),
        };

        assert_eq!(result.text_output(), "timed out");
    }

    #[test]
    fn text_projection_with_mime_type() {
        let part = CapabilityContentPart::Resource {
            uri: "file://a.txt".into(),
            mime_type: Some("text/plain".into()),
        };
        assert_eq!(
            part.text_projection(),
            "[resource] file://a.txt (text/plain)"
        );
    }

    #[test]
    fn text_projection_without_mime_type() {
        let part = CapabilityContentPart::Resource {
            uri: "file://b.txt".into(),
            mime_type: None,
        };
        assert_eq!(part.text_projection(), "[resource] file://b.txt");
    }

    #[test]
    fn from_error_builds_error_result() {
        let error = CapabilityError::with_code("E01", "something broke");
        let result = CapabilityResult::from_error(error.clone());
        assert!(result.is_error);
        assert_eq!(result.error, Some(error));
        assert_eq!(
            result.content,
            vec![CapabilityContentPart::Text {
                text: "something broke".into()
            }]
        );
    }

    #[test]
    fn text_output_joins_text_and_resource_with_newlines() {
        let result = CapabilityResult {
            content: vec![
                CapabilityContentPart::Text {
                    text: "hello".into(),
                },
                CapabilityContentPart::Resource {
                    uri: "file://x".into(),
                    mime_type: None,
                },
                CapabilityContentPart::Text {
                    text: "world".into(),
                },
            ],
            exit_code: None,
            is_error: false,
            output_truncated: false,
            error: None,
        };
        assert_eq!(result.text_output(), "hello\n[resource] file://x\nworld");
    }
}

