    }

    #[cfg(test)]
    fn shutdown_for_test(&mut self) {
        self.shutdown_for_test()
    }
}

/// The main loop running on the background thread.
fn runtime_loop(
    cmd_rx: Receiver<AgentCommand>,
    event_tx: Sender<AgentEvent>,
    provider: Arc<dyn LlmProvider>,
    mut model: String,
    workspace_root: PathBuf,
    mut tools: ToolRegistry,
    cancel_flag: Arc<AtomicBool>,
) {
    let mut turn_counter = 0u64;
    let mut conversation_history: Vec<ProviderMessage> = Vec::new();

    while let Ok(cmd) = cmd_rx.recv() {
        match cmd {
            AgentCommand::SubmitTurn { prompt } => {
                turn_counter += 1;
                let turn_id = format!("turn-{turn_counter}");
                info!(
                    "runtime: SubmitTurn id={turn_id} model={model} prompt_len={}",
                    prompt.len()
                );

                cancel_flag.store(false, Ordering::SeqCst);

                if event_tx
                    .send(AgentEvent::TurnStarted {
                        turn_id: turn_id.clone(),
                    })
                    .is_err()
                {
                    break;
                }

                if let Some(updated_history) = run_turn_with_retry(
                    &turn_id,
                    &prompt,
                    &conversation_history,
                    &*provider,
                    &model,
                    &tools,
                    &event_tx,
                    &cancel_flag,
                ) {
                    conversation_history = updated_history;
                }
            }
            AgentCommand::SetModel { model: new_model } => {
                info!("runtime: SetModel old={model} new={new_model}");
                model = new_model;
            }
            AgentCommand::RefreshAcpAgents => {
                info!(
                    "runtime: RefreshAcpAgents workspace={}",
                    workspace_root.display()
                );
                match build_tool_registry(Arc::clone(&provider), &workspace_root, &model) {
                    Ok(updated_tools) => {
                        tools = updated_tools;
                        let _ = event_tx.send(AgentEvent::AcpAgentsRefreshed);
                    }
                    Err(error) => {
                        warn!("runtime: ACP refresh failed: {error}");
                        let _ = event_tx.send(AgentEvent::AcpAgentsRefreshFailed { error });
                    }
                }
            }
            AgentCommand::Cancel => {
                debug!("runtime: Cancel received");
                cancel_flag.store(true, Ordering::SeqCst);
            }
            AgentCommand::Shutdown => {
                info!("runtime: Shutdown");
                break;
            }
        }
    }
}

fn transient_retry_app_log_message(turn_id: &str, attempt: u32, _error: &str) -> String {
    format!(
        "runtime: transient turn retry scheduled turn_id={turn_id} attempt={attempt} max_retries={MAX_TRANSIENT_RETRIES} error_kind=ProviderTransient details=redacted"
    )
}

fn transient_retry_exhausted_app_log_message(turn_id: &str, retries: u32, _error: &str) -> String {
    format!(
        "runtime: transient turn failed turn_id={turn_id} retries={retries} error_kind=ProviderTransient details=redacted"
    )
}

/// Execute a turn with up to `MAX_TRANSIENT_RETRIES` retries on transient errors.
#[allow(clippy::too_many_arguments)]
fn run_turn_with_retry(
    turn_id: &str,
    prompt: &str,
    history: &[ProviderMessage],
    provider: &dyn LlmProvider,
    model: &str,
    tools: &ToolRegistry,
    event_tx: &Sender<AgentEvent>,
    cancel_flag: &Arc<AtomicBool>,
) -> Option<Vec<ProviderMessage>> {
    for attempt in 0..=MAX_TRANSIENT_RETRIES {
        if cancel_flag.load(Ordering::SeqCst) {
            info!("runtime: turn {turn_id} cancelled before attempt {attempt}");
            emit_structured_event(
                log::Level::Info,
                module_path!(),
                "turn_failed",
                "runtime turn cancelled before retry attempt",
                None,
                Some(turn_id),
                None,
                None,
                Some("Cancelled"),
            );
            let _ = event_tx.send(AgentEvent::TurnFailed {
                kind: RuntimeErrorKind::Cancelled,
                error: "cancelled".to_string(),
            });
            return None;
        }

        let mut messages = history.to_vec();
        messages.push(ProviderMessage::User {
            content: prompt.to_string(),
        });
        let observer = ChannelObserver { tx: event_tx };
        let result = execute_turn(
            &mut messages,
            provider,
            model,
            tools,
            &observer,
            cancel_flag,
        );

        match result {
            TurnOutcome::Complete => {
                let _ = event_tx.send(AgentEvent::TurnComplete);
                return Some(messages);
            }
            TurnOutcome::Cancelled => {
                emit_structured_event(
                    log::Level::Info,
                    module_path!(),
                    "turn_failed",
                    "runtime turn cancelled during execution",
                    None,
                    Some(turn_id),
                    None,
                    None,
                    Some("Cancelled"),
                );
                return None;
            }
            TurnOutcome::TransientError(err) => {
                if attempt < MAX_TRANSIENT_RETRIES {
                    warn!(
                        "{}",
                        transient_retry_app_log_message(turn_id, attempt, &err)
                    );
                    std::thread::sleep(std::time::Duration::from_millis(500));
                } else {
                    let message = transient_retry_exhausted_app_log_message(turn_id, attempt, &err);
                    warn!("{message}");
                    emit_structured_event(
                        log::Level::Warn,
                        module_path!(),
                        "turn_failed",
                        &message,
                        None,
                        Some(turn_id),
                        None,
                        None,
                        Some("ProviderTransient"),
                    );
                    let _ = event_tx.send(AgentEvent::TurnFailed {
                        kind: RuntimeErrorKind::ProviderTransient,
                        error: err,
                    });
                    return None;
                }
            }
            TurnOutcome::FatalError { kind, error } => {
                let message = format!("runtime: turn {turn_id} fatal error (details redacted)");
                warn!("{message} ({kind:?})");
                let error_kind = format!("{kind:?}");
                emit_structured_event(
                    log::Level::Warn,
                    module_path!(),
                    "turn_failed",
                    &message,
                    None,
                    Some(turn_id),
                    None,
                    None,
                    Some(&error_kind),
                );
                let _ = event_tx.send(AgentEvent::TurnFailed { kind, error });
                return None;
            }
        }
    }

    None
}

fn build_tool_registry(
    provider: Arc<dyn LlmProvider>,
    workspace_root: &Path,
    model: &str,
) -> Result<ToolRegistry, String> {
    let ctx = ToolBuildContext {
        workspace_root: workspace_root.to_path_buf(),
        provider,
        model: model.to_string(),
    };
    let mut tools = register_builtin_tools(&ctx, ToolBuildProfile::MainRuntime)?;

    register_acp_tools(&mut tools, workspace_root)?;

    Ok(tools)
}

fn register_acp_tools(tools: &mut ToolRegistry, workspace_root: &Path) -> Result<(), String> {
    let config_path = workspace_root.join(AGENTS_CONFIG_PATH);
    if !config_path.exists() {
        return Ok(());
    }

    let config = load_agents_config_from_path(&config_path)
        .map_err(|error| format!("{}: {error}", config_path.display()))?;
    let transport = ReqwestAcpTransport::new().map_err(|error| error.to_string())?;
    let mut seen_agent_keys = HashSet::new();
    let reserved_tool_names = tools
        .specs()
        .into_iter()
        .map(|spec| spec.name)
        .collect::<HashSet<_>>();
    let mut seen_tool_names = reserved_tool_names.clone();

    for configured in config.agents.into_iter().filter(|agent| agent.enabled) {
        if reserved_tool_names.contains(&configured.name) {
            return Err(format!(
                "ACP tool name collides with built-in tool: {}",
                configured.name
            ));
        }
        let metadata = transport
            .get_agent(&configured.endpoint, &configured.agent_id)
            .map_err(|error| error.to_string())?;
        if !seen_tool_names.insert(configured.name.clone()) {
            return Err(format!("duplicate ACP tool name: {}", configured.name));
        }
        seen_agent_keys.insert((
            normalize_endpoint(&configured.endpoint),
            configured.agent_id,
        ));
        tools.register(Box::new(AcpAgentTool::with_transport(
            configured.name,
            normalize_endpoint(&configured.endpoint),
            metadata,
            transport.clone(),
        )));
    }

    let discovery = AcpDiscovery::new(config.discovery.endpoints, transport.clone());
    let report = discovery.discover(&seen_agent_keys);
    if report.errors.is_empty() {
        debug!("runtime: ACP discovery completed without endpoint errors");
    } else {
        let successful_count = report.agents.len();
        for error in &report.errors {
            warn!("runtime: ACP discovery endpoint failed: {error}");
        }
        warn!(
            "runtime: ACP discovery completed with {} successful agents and {} endpoint errors",
            successful_count,
            report.errors.len()
        );
    }
    for discovered in report.agents {
        let tool_name = discovered.metadata.name.clone();
        if reserved_tool_names.contains(&tool_name) {
            warn!(
                "runtime: skipped discovered ACP agent with built-in tool name collision {tool_name}"
            );
            continue;
        }
        if !seen_tool_names.insert(tool_name.clone()) {
            warn!("runtime: skipped discovered ACP agent with duplicate tool name {tool_name}");
            continue;
        }
        tools.register(Box::new(AcpAgentTool::with_transport(
            tool_name,
            discovered.endpoint,
            discovered.metadata,
            transport.clone(),
        )));
    }

    Ok(())
}

use super::protocol::AgentEvent;
use crate::agent::tools::ToolKind;
use log::warn;

/// The state of the current turn in the agent loop.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum TurnState {
    Idle,
    Streaming { turn_id: String },
    Done,
    Failed { error: String },
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ActiveToolStatus {
    Running,
    Success,
    Error,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ActiveTool {
    pub call_id: String,
    pub tool_name: String,
    pub kind: ToolKind,
    pub status: ActiveToolStatus,
}

/// Blazar-owned agent runtime state.
///
/// Lives in `ChatApp` as product state — never in rendering helpers.
/// Follows the ReAct + state-machine pattern: each event from the
/// runtime drives a deterministic state transition.
#[derive(Debug)]
pub struct AgentRuntimeState {
    pub turn_state: TurnState,
    pub turn_count: u64,
    /// Partial response text accumulated during the current streaming turn.
    pub streaming_text: String,
    pub active_tools: Vec<ActiveTool>,
    pub tool_call_count: u64,
}

impl Default for AgentRuntimeState {
    fn default() -> Self {
        Self {
            turn_state: TurnState::Idle,
            turn_count: 0,
            streaming_text: String::new(),
            active_tools: Vec::new(),
            tool_call_count: 0,
        }
    }
}

impl AgentRuntimeState {
    /// Apply an agent event, returning `true` if the turn state enum changed.
    pub fn apply_event(&mut self, event: &AgentEvent) -> bool {
        match event {
            AgentEvent::TurnStarted { turn_id } => {
                self.turn_state = TurnState::Streaming {
                    turn_id: turn_id.clone(),
                };
                self.turn_count += 1;
                self.streaming_text.clear();
                self.active_tools.clear();
                true
            }
            AgentEvent::TextDelta { text } => {
                self.streaming_text.push_str(text);
                false
            }
            AgentEvent::ThinkingDelta { .. } => {
                // Thinking deltas don't accumulate in state — only in timeline.
                false
            }
            AgentEvent::UsageUpdated(_) => false,
            AgentEvent::ToolCallStarted {
                call_id,
                tool_name,
                kind,
                ..
            } => {
                if self
                    .active_tools
                    .iter()
                    .find(|active_tool| active_tool.call_id == *call_id)
                    .is_some()
                {
                    warn!(
                        "agent state: duplicate ToolCallStarted for call_id={call_id} tool={tool_name}; ignoring duplicate start"
                    );
                } else {
                    self.active_tools.push(ActiveTool {
                        call_id: call_id.clone(),
                        tool_name: tool_name.clone(),
                        kind: *kind,
                        status: ActiveToolStatus::Running,
                    });
                    self.tool_call_count += 1;
                }
                false
            }
            AgentEvent::ToolCallCompleted {
                call_id, is_error, ..
            } => {
                if let Some(active_tool) = self
                    .active_tools
                    .iter_mut()
                    .find(|active_tool| active_tool.call_id == *call_id)
                {
                    active_tool.status = if *is_error {
                        ActiveToolStatus::Error
                    } else {
                        ActiveToolStatus::Success
                    };
                } else {
                    warn!(
                        "agent state: ToolCallCompleted for unknown call_id={call_id}; ignoring completion"
                    );
                }
                false
            }
            AgentEvent::AcpAgentsRefreshed | AgentEvent::AcpAgentsRefreshFailed { .. } => false,
            AgentEvent::TurnComplete => {
                self.turn_state = TurnState::Done;
                self.active_tools.clear();
                true
            }
            AgentEvent::TurnFailed { error, .. } => {
                self.turn_state = TurnState::Failed {
                    error: error.clone(),
                };
                self.active_tools.clear();
                true
            }
        }
    }

    /// Whether the agent is currently processing a turn.
    pub fn is_busy(&self) -> bool {
        matches!(self.turn_state, TurnState::Streaming { .. })
    }
}

use serde_json::Value;

use super::{Tool, ToolKind, ToolResult, ToolSpec};
use crate::agent::acp_discovery::{
    AcpAgentMetadata, AcpClientError, AcpTransport, ReqwestAcpTransport, poll_run_to_completion,
};

const MAX_RUN_POLLS: usize = 40;

// The official Agent Client Protocol Rust SDK is aimed primarily at stdio/tokio
// role wiring. Blazar currently needs a blocking tool-facing adapter for ACP
// HTTP endpoints, so we keep that transport behind `AcpTransport` to make a
// later SDK-backed bridge a localized follow-up instead of a runtime rewrite.
pub struct AcpAgentTool<T = ReqwestAcpTransport> {
    tool_name: String,
    endpoint: String,
    metadata: AcpAgentMetadata,
    transport: T,
}

impl AcpAgentTool<ReqwestAcpTransport> {
    pub fn new(
        tool_name: impl Into<String>,
        endpoint: impl Into<String>,
        metadata: AcpAgentMetadata,
    ) -> Result<Self, AcpClientError> {
        Ok(Self::with_transport(
            tool_name,
            endpoint,
            metadata,
            ReqwestAcpTransport::new()?,
        ))
    }
}

impl<T> AcpAgentTool<T> {
    pub fn with_transport(
        tool_name: impl Into<String>,
        endpoint: impl Into<String>,
        metadata: AcpAgentMetadata,
        transport: T,
    ) -> Self {
        Self {
            tool_name: tool_name.into(),
            endpoint: endpoint.into(),
            metadata,
            transport,
        }
    }
}

impl<T> Tool for AcpAgentTool<T>
where
    T: AcpTransport,
{
    fn spec(&self) -> ToolSpec {
        ToolSpec {
            name: self.tool_name.clone(),
            description: self.metadata.description.clone(),
            parameters: self.metadata.input_schema.clone(),
        }
    }

    fn kind(&self) -> ToolKind {
        ToolKind::Agent { is_acp: true }
    }

    fn execute(&self, args: Value) -> ToolResult {
        let run_id = match self
            .transport
            .create_run(&self.endpoint, &self.metadata.id, &args)
        {
            Ok(run_id) => run_id,
            Err(error) => {
                return ToolResult::failure(format!("agent unreachable: {}", error));
            }
        };

        match poll_run_to_completion(&self.transport, &self.endpoint, &run_id, MAX_RUN_POLLS) {
            Ok(result) => result,
            Err(error) => ToolResult::failure(format!("ACP run failed: {error}")),
        }
    }
}

