/// Runs a sub-agent turn. Abstracted so tests can provide a simple
/// implementation without invoking a real LLM provider.
pub(crate) trait TurnRunner: Send + Sync {
    fn run_turn(
        &self,
        messages: &mut Vec<ProviderMessage>,
        tools: &ToolRegistry,
        cancel_flag: &Arc<AtomicBool>,
    ) -> TurnOutcome;
}

/// Builds a tool registry for a sub-agent. Abstracted so tests can
/// skip real tool registration.
pub(crate) trait ToolRegistryFactory: Send + Sync {
    fn create(
        &self,
        ctx: &ToolBuildContext,
        profile: ToolBuildProfile,
    ) -> Result<ToolRegistry, String>;
}

/// Production implementation: calls `execute_turn` with `SilentObserver`.
struct DefaultTurnRunner {
    provider: Arc<dyn LlmProvider>,
    model: String,
}

impl TurnRunner for DefaultTurnRunner {
    fn run_turn(
        &self,
        messages: &mut Vec<ProviderMessage>,
        tools: &ToolRegistry,
        cancel_flag: &Arc<AtomicBool>,
    ) -> TurnOutcome {
        execute_turn(
            messages,
            &*self.provider,
            &self.model,
            tools,
            &SilentObserver,
            cancel_flag,
        )
    }
}

/// Production implementation: delegates to `register_builtin_tools`.
struct DefaultToolRegistryFactory;

impl ToolRegistryFactory for DefaultToolRegistryFactory {
    fn create(
        &self,
        ctx: &ToolBuildContext,
        profile: ToolBuildProfile,
    ) -> Result<ToolRegistry, String> {
        register_builtin_tools(ctx, profile)
    }
}

/// A tool that delegates work to a sub-agent turn.
///
/// When the parent agent invokes this tool, a fresh `execute_turn` is
/// run with [`SilentObserver`] so intermediate events are discarded.
/// The sub-agent has its own tool registry (workspace-scoped) and
/// returns its final assistant text as the tool result.
pub struct AgentTool {
    name: String,
    description: String,
    provider: Arc<dyn LlmProvider>,
    model: String,
    workspace_root: PathBuf,
    turn_runner: Box<dyn TurnRunner>,
    registry_factory: Box<dyn ToolRegistryFactory>,
}

impl AgentTool {
    pub fn new(
        name: impl Into<String>,
        description: impl Into<String>,
        provider: Arc<dyn LlmProvider>,
        model: impl Into<String>,
        workspace_root: PathBuf,
    ) -> Self {
        let model = model.into();
        Self {
            name: name.into(),
            description: description.into(),
            turn_runner: Box::new(DefaultTurnRunner {
                provider: Arc::clone(&provider),
                model: model.clone(),
            }),
            registry_factory: Box::new(DefaultToolRegistryFactory),
            provider,
            model,
            workspace_root,
        }
    }

    #[cfg(test)]
    pub(crate) fn with_deps(
        name: impl Into<String>,
        description: impl Into<String>,
        provider: Arc<dyn LlmProvider>,
        model: impl Into<String>,
        workspace_root: PathBuf,
        turn_runner: Box<dyn TurnRunner>,
        registry_factory: Box<dyn ToolRegistryFactory>,
    ) -> Self {
        Self {
            name: name.into(),
            description: description.into(),
            turn_runner,
            registry_factory,
            provider,
            model: model.into(),
            workspace_root,
        }
    }
}

impl Tool for AgentTool {
    fn spec(&self) -> ToolSpec {
        ToolSpec {
            name: self.name.clone(),
            description: self.description.clone(),
            parameters: json!({
                "type": "object",
                "properties": {
                    "prompt": {
                        "type": "string",
                        "description": "The instruction or question for this sub-agent."
                    }
                },
                "required": ["prompt"],
                "additionalProperties": false
            }),
        }
    }

    fn kind(&self) -> ToolKind {
        ToolKind::Agent { is_acp: false }
    }

    fn execute(&self, args: Value) -> ToolResult {
        let Some(prompt) = args.get("prompt").and_then(|v| v.as_str()) else {
            return ToolResult::failure("agent tool requires a string 'prompt' argument");
        };

        let ctx = ToolBuildContext {
            workspace_root: self.workspace_root.clone(),
            provider: Arc::clone(&self.provider),
            model: self.model.clone(),
        };
        let tools = match self.registry_factory.create(&ctx, ToolBuildProfile::SubAgent) {
            Ok(t) => t,
            Err(e) => return ToolResult::failure(format!("sub-agent tool assembly failed: {e}")),
        };

        let mut messages = vec![ProviderMessage::User {
            content: prompt.to_string(),
        }];

        let cancel_flag = Arc::new(AtomicBool::new(false));

        let outcome = self.turn_runner.run_turn(&mut messages, &tools, &cancel_flag);

        match outcome {
            TurnOutcome::Complete => {
                let text = messages
                    .iter()
                    .rev()
                    .find_map(|msg| match msg {
                        ProviderMessage::Assistant { content } => Some(content.clone()),
                        _ => None,
                    })
                    .unwrap_or_default();
                ToolResult::success(text)
            }
            TurnOutcome::Cancelled => ToolResult::failure("sub-agent turn was cancelled"),
            TurnOutcome::TransientError(err) => {
                ToolResult::failure(format!("sub-agent error: {err}"))
            }
            TurnOutcome::FatalError { error, .. } => {
                ToolResult::failure(format!("sub-agent error: {error}"))
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::agent::runtime::RuntimeErrorKind;
    use crate::provider::echo::EchoProvider;

    /// A turn runner that appends an assistant message and returns a preset outcome.
    struct StubTurnRunner {
        outcome: TurnOutcome,
        assistant_text: Option<String>,
    }

    impl TurnRunner for StubTurnRunner {
        fn run_turn(
            &self,
            messages: &mut Vec<ProviderMessage>,
            _tools: &ToolRegistry,
            _cancel_flag: &Arc<AtomicBool>,
        ) -> TurnOutcome {
            if let Some(text) = &self.assistant_text {
                messages.push(ProviderMessage::Assistant {
                    content: text.clone(),
                });
            }
            match &self.outcome {
                TurnOutcome::Complete => TurnOutcome::Complete,
                TurnOutcome::Cancelled => TurnOutcome::Cancelled,
                TurnOutcome::TransientError(e) => TurnOutcome::TransientError(e.clone()),
                TurnOutcome::FatalError { kind, error } => TurnOutcome::FatalError {
                    kind: *kind,
                    error: error.clone(),
                },
            }
        }
    }

    /// A factory that returns an empty registry and asserts the expected profile.
    struct StubRegistryFactory;

    impl ToolRegistryFactory for StubRegistryFactory {
        fn create(
            &self,
            _ctx: &ToolBuildContext,
            profile: ToolBuildProfile,
        ) -> Result<ToolRegistry, String> {
            assert_eq!(
                profile,
                ToolBuildProfile::SubAgent,
                "AgentTool must request SubAgent profile"
            );
            Ok(ToolRegistry::new(PathBuf::from("/tmp/test-workspace")))
        }
    }

    /// A factory that always fails.
    struct FailingRegistryFactory;

    impl ToolRegistryFactory for FailingRegistryFactory {
        fn create(
            &self,
            _ctx: &ToolBuildContext,
            _profile: ToolBuildProfile,
        ) -> Result<ToolRegistry, String> {
            Err("simulated registry failure".to_string())
        }
    }

    fn make_agent(runner: StubTurnRunner, factory: impl ToolRegistryFactory + 'static) -> AgentTool {
        AgentTool::with_deps(
            "sub_agent",
            "test agent",
            Arc::new(EchoProvider::default()),
            "test-model",
            PathBuf::from("/tmp/test-workspace"),
            Box::new(runner),
            Box::new(factory),
        )
    }

    #[test]
    fn missing_prompt_returns_error() {
        let runner = StubTurnRunner {
            outcome: TurnOutcome::Complete,
            assistant_text: None,
        };
        let tool = make_agent(runner, StubRegistryFactory);
        let result = tool.execute(json!({}));
        assert!(result.is_error);
        assert!(result.text_output().contains("prompt"));
    }

    #[test]
    fn registry_failure_returns_error() {
        let runner = StubTurnRunner {
            outcome: TurnOutcome::Complete,
            assistant_text: None,
        };
        let tool = make_agent(runner, FailingRegistryFactory);
        let result = tool.execute(json!({"prompt": "do something"}));
        assert!(result.is_error);
        assert!(result.text_output().contains("sub-agent tool assembly failed"));
    }

    #[test]
    fn complete_with_assistant_text_returns_success() {
        let runner = StubTurnRunner {
            outcome: TurnOutcome::Complete,
            assistant_text: Some("done!".to_string()),
        };
        let tool = make_agent(runner, StubRegistryFactory);
        let result = tool.execute(json!({"prompt": "do something"}));
        assert!(!result.is_error);
        assert_eq!(result.text_output(), "done!");
    }

    #[test]
    fn complete_without_assistant_text_returns_empty() {
        let runner = StubTurnRunner {
            outcome: TurnOutcome::Complete,
            assistant_text: None,
        };
        let tool = make_agent(runner, StubRegistryFactory);
        let result = tool.execute(json!({"prompt": "do something"}));
        assert!(!result.is_error);
        assert_eq!(result.text_output(), "");
    }

    #[test]
    fn cancelled_outcome_returns_failure() {
        let runner = StubTurnRunner {
            outcome: TurnOutcome::Cancelled,
            assistant_text: None,
        };
        let tool = make_agent(runner, StubRegistryFactory);
        let result = tool.execute(json!({"prompt": "do something"}));
        assert!(result.is_error);
        assert!(result.text_output().contains("cancelled"));
    }

    #[test]
    fn transient_error_returns_failure() {
        let runner = StubTurnRunner {
            outcome: TurnOutcome::TransientError("timeout".to_string()),
            assistant_text: None,
        };
        let tool = make_agent(runner, StubRegistryFactory);
        let result = tool.execute(json!({"prompt": "do something"}));
        assert!(result.is_error);
        assert!(result.text_output().contains("timeout"));
    }

    #[test]
    fn fatal_error_returns_failure() {
        let runner = StubTurnRunner {
            outcome: TurnOutcome::FatalError {
                kind: RuntimeErrorKind::ToolExecution,
                error: "iteration limit".to_string(),
            },
            assistant_text: None,
        };
        let tool = make_agent(runner, StubRegistryFactory);
        let result = tool.execute(json!({"prompt": "do something"}));
        assert!(result.is_error);
        assert!(result.text_output().contains("iteration limit"));
    }
}

use super::{
    BuiltinToolDescriptor, BuiltinToolProfiles, ContentPart, Tool, ToolBuildContext, ToolResult,
    ToolSpec, canonical_workspace_root, resolve_workspace_path,
};
use serde_json::{Value, json};
use std::fs;
use std::path::{Path, PathBuf};

const MAX_DEPTH: usize = 2;

inventory::submit! {
    BuiltinToolDescriptor {
        name: "list_dir",
        profiles: BuiltinToolProfiles::Both,
        build: |ctx: &ToolBuildContext| Box::new(ListDirTool::new(ctx.workspace_root.clone())),
    }
}
const MAX_ENTRIES: usize = 200;

pub struct ListDirTool {
    workspace_root: PathBuf,
}

impl ListDirTool {
    pub fn new(workspace_root: PathBuf) -> Self {
        Self { workspace_root }
    }

    fn visit(
        path: &Path,
        workspace_root: &Path,
        prefix: &str,
        depth: usize,
        lines: &mut Vec<String>,
    ) -> Result<bool, String> {
        if depth > MAX_DEPTH {
            return Ok(false);
        }

        let entries = fs::read_dir(path)
            .map_err(|error| format!("cannot list {}: {error}", path.display()))?;

        let mut entries = entries
            .collect::<Result<Vec<_>, _>>()
            .map_err(|error| format!("cannot list {}: {error}", path.display()))?;
        entries.sort_by_key(|entry| entry.path());

        for entry in entries {
            if lines.len() >= MAX_ENTRIES {
                return Ok(true);
            }

            let file_name = entry.file_name().to_string_lossy().to_string();
            let child_path = entry.path();
            let canonical_child_path = fs::canonicalize(&child_path)
                .map_err(|error| format!("cannot resolve {}: {error}", child_path.display()))?;
            if !canonical_child_path.starts_with(workspace_root) {
                return Err(format!(
                    "cannot list {}: path escapes workspace root",
                    child_path.display()
                ));
            }

            if child_path.is_dir() {
                let rendered = format!("{prefix}{file_name}/");
                lines.push(rendered.clone());

                if depth < MAX_DEPTH
                    && Self::visit(
                        &canonical_child_path,
                        workspace_root,
                        &rendered,
                        depth + 1,
                        lines,
                    )?
                {
                    return Ok(true);
                }
            } else {
                lines.push(format!("{prefix}{file_name}"));
            }
        }

        Ok(false)
    }
}

impl Tool for ListDirTool {
    fn spec(&self) -> ToolSpec {
        ToolSpec {
            name: "list_dir".into(),
            description: "List files and directories in the workspace up to 2 levels deep. Defaults to workspace root. Use to explore project structure before reading or writing files.".into(),
            parameters: json!({
                "type": "object",
                "properties": {
                    "path": {
                        "type": "string",
                        "description": "Relative directory path inside the workspace to list."
                    }
                },
                "required": ["path"],
                "additionalProperties": false
            }),
        }
    }

    fn execute(&self, args: Value) -> ToolResult {
        let Some(path) = args.get("path").and_then(|value| value.as_str()) else {
            return ToolResult::failure("list_dir requires a string path");
        };

        let canonical_root = match canonical_workspace_root(&self.workspace_root) {
            Ok(root) => root,
            Err(error) => return ToolResult::failure(error),
        };
        let full_path = match resolve_workspace_path(&self.workspace_root, path) {
            Ok(path) => path,
            Err(error) => return ToolResult::failure(error),
        };
        if !full_path.is_dir() {
            return ToolResult::failure(format!(
                "cannot list {}: not a directory",
                full_path.display()
            ));
        }

        let mut lines = Vec::new();
        let truncated = match Self::visit(&full_path, &canonical_root, "", 0, &mut lines) {
            Ok(truncated) => truncated,
            Err(error) => return ToolResult::failure(error),
        };

        let mut output = lines.join("\n");
        if truncated {
            output.push_str("\n[list truncated]");
        }
        ToolResult {
            content: vec![ContentPart::text(output)],
            exit_code: None,
            is_error: false,
            output_truncated: truncated,
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use serde_json::json;
    use std::time::{SystemTime, UNIX_EPOCH};

    fn fresh_workspace(label: &str) -> PathBuf {
        let suffix = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_nanos();
        let path = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("target")
            .join("test-workspaces")
            .join(format!("blazar-list-dir-{label}-{suffix}"));
        fs::create_dir_all(&path).unwrap();
        path
    }

    #[test]
    fn execute_lists_nested_directories() {
        let ws = fresh_workspace("nested");
        fs::create_dir_all(ws.join("src/models")).unwrap();
        fs::write(ws.join("src/main.rs"), "fn main() {}").unwrap();
        fs::write(ws.join("src/models/user.rs"), "struct User;").unwrap();
        fs::write(ws.join("README.md"), "# hello").unwrap();

        let tool = ListDirTool::new(ws);
        let result = tool.execute(json!({"path": "."}));

        assert!(!result.is_error);
        let output = result.text_output();
        assert!(output.contains("src/"));
        assert!(output.contains("README.md"));
        assert!(output.contains("src/main.rs"));
        assert!(output.contains("src/models/"));
    }

    #[test]
    fn execute_handles_empty_directory() {
        let ws = fresh_workspace("empty");
        fs::create_dir_all(ws.join("empty_sub")).unwrap();

        let tool = ListDirTool::new(ws);
        let result = tool.execute(json!({"path": "empty_sub"}));

        assert!(!result.is_error);
        assert!(result.text_output().is_empty());
    }

    #[test]
    fn execute_handles_missing_path() {
        let ws = fresh_workspace("missing");

        let tool = ListDirTool::new(ws);
        let result = tool.execute(json!({"path": "nonexistent"}));

        assert!(result.is_error);
        assert!(result.text_output().contains("cannot resolve"));
    }

    #[test]
    fn execute_rejects_path_escaping_workspace() {
        let ws = fresh_workspace("escape");

        let tool = ListDirTool::new(ws);
        let result = tool.execute(json!({"path": "../.."}));

        assert!(result.is_error);
    }

    #[test]
    fn execute_rejects_non_directory_path() {
        let ws = fresh_workspace("not-dir");
        fs::write(ws.join("file.txt"), "hello").unwrap();

        let tool = ListDirTool::new(ws);
        let result = tool.execute(json!({"path": "file.txt"}));

        assert!(result.is_error);
        assert!(result.text_output().contains("not a directory"));
    }

    #[test]
    fn execute_depth_limit_stops_recursion() {
        let ws = fresh_workspace("depth");
        // Create directories deeper than MAX_DEPTH (2)
        fs::create_dir_all(ws.join("a/b/c/d")).unwrap();
        fs::write(ws.join("a/b/c/d/deep.txt"), "deep").unwrap();

        let tool = ListDirTool::new(ws);
        let result = tool.execute(json!({"path": "."}));

        assert!(!result.is_error);
        let output = result.text_output();
        // Level 0: "a/", Level 1: "a/b/", Level 2: "a/b/c/" — depth=2 is the max
        assert!(output.contains("a/"));
        assert!(output.contains("a/b/"));
        assert!(output.contains("a/b/c/"));
        // "d/" is at depth 3, should not appear
        assert!(!output.contains("d/"));
        assert!(!output.contains("deep.txt"));
    }

    #[cfg(unix)]
    #[test]
    fn execute_rejects_symlink_escaping_workspace() {
        use std::os::unix::fs as unix_fs;

        let ws = fresh_workspace("symlink-escape");
        let outside = fresh_workspace("symlink-outside");
        fs::write(outside.join("secret.txt"), "secret").unwrap();

        unix_fs::symlink(&outside, ws.join("escape_link")).unwrap();

        let tool = ListDirTool::new(ws);
        let result = tool.execute(json!({"path": "."}));

        assert!(result.is_error);
        assert!(result.text_output().contains("escapes workspace root"));
    }

    #[test]
    fn execute_fails_with_invalid_workspace_root() {
        let ws = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
            .join("target")
            .join("test-workspaces")
            .join("nonexistent-workspace-root");

        let tool = ListDirTool::new(ws);
        let result = tool.execute(json!({"path": "."}));

        assert!(result.is_error);
        assert!(result.text_output().contains("cannot resolve"));
    }
}

/// Governance metadata for Tool-facade compatibility.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ToolCompatibilityTier {
    /// Canonical implementation target inside the Capability Kernel architecture.
    KernelNative,
    /// Transitional Tool-facade shim retained for migration compatibility.
    CompatibilityBridge,
}

/// Static compatibility governance for known built-in tools.
pub fn compatibility_tier_for_name(name: &str) -> Option<ToolCompatibilityTier> {
    match name {
        "bash" => Some(ToolCompatibilityTier::CompatibilityBridge),
        "vet" => Some(ToolCompatibilityTier::CompatibilityBridge),
        _ => None,
    }
}

use super::{
    BuiltinToolDescriptor, BuiltinToolProfiles, ResourceAccess, ResourceClaim, Tool,
    ToolBuildContext, ToolResult, ToolSpec, normalize_workspace_resource_claim,
    resolve_workspace_path,
};
use serde_json::{Value, json};
use std::fs;
use std::path::PathBuf;

const MAX_FILE_BYTES: usize = 100 * 1024;

inventory::submit! {
    BuiltinToolDescriptor {
        name: "read_file",
        profiles: BuiltinToolProfiles::Both,
        build: |ctx: &ToolBuildContext| Box::new(ReadFileTool::new(ctx.workspace_root.clone())),
    }
}

pub struct ReadFileTool {
    workspace_root: PathBuf,
}

impl ReadFileTool {
    pub fn new(workspace_root: PathBuf) -> Self {
        Self { workspace_root }
    }
}

impl Tool for ReadFileTool {
    fn spec(&self) -> ToolSpec {
        ToolSpec {
            name: "read_file".into(),
            description: "Read a UTF-8 text file from the workspace. Path is relative to workspace root (e.g. \"src/main.rs\"). Returns the full file content.".into(),
            parameters: json!({
                "type": "object",
                "properties": {
                    "path": {
                        "type": "string",
                        "description": "Relative path to a UTF-8 text file inside the workspace."
                    }
                },
                "required": ["path"],
                "additionalProperties": false
            }),
        }
    }

    fn resource_claims(&self, args: &Value) -> Vec<ResourceClaim> {
        args.get("path")
            .and_then(Value::as_str)
            .and_then(|path| normalize_workspace_resource_claim(&self.workspace_root, path).ok())
            .map(|resource| {
                vec![ResourceClaim {
                    resource,
                    access: ResourceAccess::ReadOnly,
                }]
            })
            .unwrap_or_default()
    }

    fn execute(&self, args: Value) -> ToolResult {
        let Some(path) = args.get("path").and_then(|value| value.as_str()) else {
            return ToolResult::failure("read_file requires a string path");
        };

        let full_path = match resolve_workspace_path(&self.workspace_root, path) {
            Ok(path) => path,
            Err(error) => return ToolResult::failure(error),
        };

        match fs::metadata(&full_path) {
            Ok(metadata) if metadata.len() > MAX_FILE_BYTES as u64 => {
                ToolResult::failure("file exceeds 100KB limit")
            }
            Ok(_) => match fs::read(&full_path) {
                Ok(bytes) => match String::from_utf8(bytes) {
                    Ok(text) => ToolResult::success(text),
                    Err(error) => ToolResult::failure(format!("file is not valid UTF-8: {error}")),
                },
                Err(error) => {
                    ToolResult::failure(format!("cannot read {}: {error}", full_path.display()))
                }
            },
            Err(error) => {
                ToolResult::failure(format!("cannot read {}: {error}", full_path.display()))
            }
        }
    }
}

