use super::*;
use crate::chat::picker::{PickerContext, PickerItem};

impl ChatApp {
    pub(crate) fn reset_command_picker(&mut self) {
        self.picker = ModalPicker::command_palette_from_registry(&self.command_registry);
    }

    pub(crate) fn open_theme_picker(&mut self) {
        let theme_items: Vec<PickerItem> = crate::chat::theme::available_themes()
            .into_iter()
            .map(|info| PickerItem::new(info.name.clone(), info.display_name.clone()))
            .collect();
        self.picker =
            ModalPicker::with_context("Select Theme", theme_items, PickerContext::ThemeSelect);
        self.picker.open();
    }

    pub(crate) fn open_model_picker(&mut self) {
        let current = &self.model_name;
        let repo_str = self.workspace_root.to_string_lossy();
        let model_items: Vec<PickerItem> = self
            .model_metadata
            .fetch_available_models(&repo_str)
            .into_iter()
            .map(|m| {
                let label = if m.id == *current {
                    format!("{} ✓", m.id)
                } else {
                    m.id
                };
                PickerItem::new(label, m.description)
            })
            .collect();
        self.picker =
            ModalPicker::with_context("Select Model", model_items, PickerContext::ModelSelect);
        self.picker.open();
    }

    pub fn handle_action(&mut self, action: InputAction) {
        // When picker is open, route input to it
        if self.picker.is_open() {
            match action {
                InputAction::Quit => {
                    self.picker.close();
                }
                InputAction::Submit => {
                    if let Some(cmd) = self.picker.select_current() {
                        let ctx = self.picker.context;
                        self.picker.close();

                        // Sub-picker selection (no / prefix) — dispatch by context
                        if !cmd.starts_with('/') {
                            match ctx {
                                PickerContext::ThemeSelect => {
                                    self.set_theme(&cmd);
                                }
                                PickerContext::ModelSelect => {
                                    let clean = cmd.trim_end_matches(" ✓");
                                    self.set_model(clean);
                                }
                                PickerContext::Commands => {
                                    self.send_message_without_command_dispatch(&cmd);
                                }
                            }
                            self.reset_command_picker();
                            return;
                        }

                        if self.command_registry.find(&cmd).is_some() {
                            if let Err(err) =
                                self.execute_palette_command_sync(&cmd, serde_json::json!({}))
                            {
                                self.timeline
                                    .push(TimelineEntry::warning(format!("Command failed: {err}")));
                                self.scroll_offset = u16::MAX;
                            }
                            return;
                        }

                        self.send_message_without_command_dispatch(&cmd);
                    }
                }
                InputAction::ScrollUp => self.picker.move_up(),
                InputAction::ScrollDown => self.picker.move_down(),
                InputAction::PickerUp => self.picker.move_up(),
                InputAction::PickerDown => self.picker.move_down(),
                InputAction::Backspace => {
                    if self.picker.filter.is_empty() {
                        self.picker.close();
                    } else {
                        self.picker.pop_filter();
                    }
                }
                InputAction::Key(key) => {
                    if let crossterm::event::KeyCode::Char(ch) = key.code {
                        self.picker.push_filter(ch);
                    }
                }
                _ => {}
            }
            return;
        }

        match action {
            InputAction::Quit => {
                if self.is_streaming() {
                    self.cancel_turn();
                } else {
                    self.should_quit = true;
                }
            }
            InputAction::Submit => self.submit_composer(),
            InputAction::InsertNewline => {
                self.composer.insert_newline();
                self.sync_users_status_from_composer();
            }
            InputAction::ToggleMode => {
                self.user_mode = match self.user_mode {
                    UserMode::Auto => UserMode::Plan,
                    UserMode::Plan => UserMode::Auto,
                };
            }
            InputAction::ToggleDetails => self.show_details = !self.show_details,
            InputAction::ScrollUp => {
                if self.users_status_mode == StatusMode::CommandList {
                    self.scroll_users_command_window(-1);
                } else {
                    self.resolve_scroll_sentinel();
                    self.scroll_offset = self.scroll_offset.saturating_sub(3);
                }
            }
            InputAction::ScrollDown => {
                if self.users_status_mode == StatusMode::CommandList {
                    self.scroll_users_command_window(1);
                } else {
                    self.resolve_scroll_sentinel();
                    self.scroll_offset = self.scroll_offset.saturating_add(3);
                }
            }
            InputAction::Key(key) => {
                self.composer.input(key);
                self.sync_users_status_from_composer();
            }
            InputAction::Backspace => {
                self.composer.input(crossterm::event::KeyEvent::new(
                    crossterm::event::KeyCode::Backspace,
                    crossterm::event::KeyModifiers::NONE,
                ));
                self.sync_users_status_from_composer();
            }
            InputAction::Paste(text) => {
                debug!("handle_action: paste len={}", text.len());
                self.composer.insert_str(&text);
                self.sync_users_status_from_composer();
            }
            _ => {}
        }
    }
}

use super::turns::{
    extract_plan_action_names, extract_plan_title_and_body, extract_tool_call_metadata_line,
    format_tool_call_details, parse_next_step_name_line, short_action_name_from_text,
};
use super::*;
use crate::agent::runtime::RuntimeErrorKind;
use crate::observability::debug::DebugEventSnapshot;
use crate::observability::logging::{StructuredEventContext, emit_structured_event_with_context};

impl ChatApp {
    #[doc(hidden)]
    pub fn apply_agent_event_for_test(&mut self, event: AgentEvent) {
        self.apply_agent_event(event);
    }

    #[doc(hidden)]
    pub fn set_context_usage_for_test(&mut self, used_tokens: u32, max_tokens: u32) {
        self.context_usage = Some(ContextUsage {
            used_tokens,
            max_tokens,
        });
    }

    #[doc(hidden)]
    pub fn set_model_context_max_tokens_for_test(&mut self, max_tokens: Option<u32>) {
        self.model_metadata.model_context_max_tokens = max_tokens;
    }

    #[doc(hidden)]
    pub fn set_pr_label_for_test(&mut self, pr_label: Option<String>) {
        self.git_pr_label = pr_label;
    }

    #[doc(hidden)]
    pub fn set_referenced_files_for_test(&mut self, referenced_files: Vec<String>) {
        self.referenced_files = referenced_files;
    }

    pub(super) fn apply_agent_event(&mut self, event: AgentEvent) {
        let turn_id_context = self.current_turn_id().map(str::to_owned);
        let _ = self.agent_state.apply_event(&event);

        match event {
            AgentEvent::TurnStarted { turn_id } => {
                debug!("tick: TurnStarted");
                self.thinking_action_name = None;
                self.current_turn_has_thinking_entry = false;
                self.debug_recorder.start_turn(
                    &turn_id,
                    self.active_turn_kind_label(),
                    self.pending_messages.len(),
                );
                self.refresh_active_turn_status_label();
                self.scroll_offset = u16::MAX;
            }
            AgentEvent::ThinkingDelta { text } => {
                trace!("tick: ThinkingDelta len={}", text.len());
                let tail_is_thinking = self
                    .timeline
                    .last()
                    .is_some_and(|entry| entry.kind == EntryKind::Thinking);
                let in_streaming_turn = matches!(
                    self.agent_state.turn_state,
                    crate::agent::state::TurnState::Streaming { .. }
                );
                let needs_new = if in_streaming_turn && !self.current_turn_has_thinking_entry {
                    true
                } else {
                    !tail_is_thinking
                };
                if needs_new {
                    self.timeline.push(TimelineEntry::thinking(""));
                }
                if let Some(last) = self.timeline.last_mut() {
                    last.body.push_str(&text);
                    last.details.push_str(&text);
                    self.current_turn_has_thinking_entry = true;
                    if let Some(action_name) = parse_next_step_name_line(&last.body)
                        .or_else(|| stable_fallback_action_name(&last.body))
                    {
                        self.thinking_action_name = Some(action_name);
                    }
                }
                self.refresh_active_turn_status_label();
                self.scroll_offset = u16::MAX;
            }
            AgentEvent::TextDelta { text } => {
                trace!("tick: TextDelta len={}", text.len());
                let needs_new = self.timeline.last().is_none_or(|entry| {
                    !(entry.actor == Actor::Assistant && entry.kind == EntryKind::Message)
                });
                if needs_new {
                    self.timeline.push(TimelineEntry::response(""));
                }
                if let Some(last) = self.timeline.last_mut() {
                    last.body.push_str(&text);
                }
                self.scroll_offset = u16::MAX;
            }
            AgentEvent::UsageUpdated(crate::agent::protocol::AgentUsage {
                prompt_tokens: _,
                completion_tokens: _,
                total_tokens,
            }) => {
                let resolved_max = self.model_metadata.resolved_context_limit().unwrap_or(0);
                self.context_usage = Some(ContextUsage {
                    used_tokens: total_tokens,
                    max_tokens: resolved_max,
                });
                self.scroll_offset = u16::MAX;
            }
            AgentEvent::ToolCallStarted {
                call_id,
                tool_name,
                kind,
                arguments,
                batch_id,
                replay_index,
                normalized_claims,
            } => {
                self.ingest_referenced_files_from_claims(&normalized_claims);
                debug!(
                    "tick: ToolCallStarted call_id={} tool={} arguments_len={}",
                    call_id,
                    tool_name,
                    arguments.len()
                );
                let message = format!(
                    "chat tool call started call_id={call_id} tool={tool_name} arguments_len={}",
                    arguments.len()
                );
                let debug_event = self.debug_recorder.record_event(
                    "tool_call_started",
                    Some(&tool_name),
                    Some(&call_id),
                    None,
                    self.pending_messages.len(),
                    &message,
                );
                emit_structured_event_with_context(
                    log::Level::Debug,
                    module_path!(),
                    "tool_call_started",
                    &message,
                    structured_debug_context(&debug_event),
                );
                self.timeline.push(TimelineEntry::tool_call(
                    call_id,
                    tool_name,
                    kind,
                    arguments.clone(),
                    summarize_tool_arguments(&arguments),
                    append_tool_debug_details(
                        format_tool_call_details(
                            &arguments,
                            batch_id,
                            replay_index,
                            &normalized_claims,
                        ),
                        &debug_event,
                    ),
                    ToolCallStatus::Running,
                ));
                self.refresh_active_turn_status_label();
                self.scroll_offset = u16::MAX;
            }
            AgentEvent::ToolCallCompleted {
                call_id,
                output,
                is_error,
            } => {
                let completed_tool_name = self.timeline.iter().rev().find_map(|entry| match &entry
                    .kind
                {
                    EntryKind::ToolCall {
                        call_id: existing,
                        tool_name,
                        ..
                    } if existing == &call_id => Some(tool_name.clone()),
                    _ => None,
                });
                debug!(
                    "tick: ToolCallCompleted call_id={} is_error={} output_len={}",
                    call_id,
                    is_error,
                    output.len()
                );
                let message =
                    format!("chat tool call completed call_id={call_id} is_error={is_error}");
                let debug_event = self.debug_recorder.record_event(
                    "tool_call_completed",
                    completed_tool_name.as_deref(),
                    Some(&call_id),
                    None,
                    self.pending_messages.len(),
                    &message,
                );
                emit_structured_event_with_context(
                    log::Level::Debug,
                    module_path!(),
                    "tool_call_completed",
                    &message,
                    structured_debug_context(&debug_event),
                );
                if let Some(entry) = self.timeline.iter_mut().rev().find(|entry| {
                    matches!(
                        &entry.kind,
                        EntryKind::ToolCall { call_id: existing, .. } if existing == &call_id
                    )
                }) {
                    entry.body = summarize_tool_output(&output);
                    let details = match extract_tool_call_metadata_line(&entry.details) {
                        Some(metadata_line) if output.is_empty() => metadata_line,
                        Some(metadata_line) => format!("{output}\n\n{metadata_line}"),
                        None => output,
                    };
                    entry.details = append_tool_debug_details(details, &debug_event);
                    if let EntryKind::ToolCall { status, .. } = &mut entry.kind {
                        *status = if is_error {
                            ToolCallStatus::Error
                        } else {
                            ToolCallStatus::Success
                        };
                    }
                }
                self.refresh_active_turn_status_label();
                self.scroll_offset = u16::MAX;
            }
            AgentEvent::AcpAgentsRefreshed => {
                self.timeline
                    .push(TimelineEntry::hint("ACP agent discovery complete."));
                self.dispatch_next_queued();
                self.scroll_offset = u16::MAX;
            }
            AgentEvent::AcpAgentsRefreshFailed { error } => {
                warn!("tick: AcpAgentsRefreshFailed error={error}");
                self.timeline.push(TimelineEntry::warning(format!(
                    "ACP agent discovery failed: {error}"
                )));
                self.dispatch_next_queued();
                self.scroll_offset = u16::MAX;
            }
            AgentEvent::TurnComplete => {
                debug!("tick: TurnComplete");
                self.debug_recorder.record_event(
                    "turn_complete",
                    None,
                    None,
                    None,
                    self.pending_messages.len(),
                    "chat turn complete",
                );
                self.debug_recorder.finish_turn("completed", None, None);
                if self.active_turn_kind == Some(TurnKind::Plan) {
                    self.finalize_plan_response();
                }
                self.thinking_action_name = None;
                self.current_turn_has_thinking_entry = false;
                self.active_turn_kind = None;
                self.active_turn_title = None;
                self.dispatch_next_queued();
            }
            AgentEvent::TurnFailed { kind, error } => {
                if kind == RuntimeErrorKind::Cancelled {
                    debug!("tick: TurnCancelled");
                    self.timeline.push(TimelineEntry::hint("Turn cancelled."));
                } else {
                    let safe_log_message =
                        turn_failed_app_log_message(kind, turn_id_context.as_deref());
                    warn!("{safe_log_message}");
                    let debug_event = self.debug_recorder.record_event(
                        "turn_failed",
                        None,
                        None,
                        Some(runtime_error_kind_label(kind)),
                        self.pending_messages.len(),
                        &safe_log_message,
                    );
                    emit_structured_event_with_context(
                        log::Level::Warn,
                        module_path!(),
                        "turn_failed",
                        &safe_log_message,
                        structured_debug_context(&debug_event),
                    );
                    let details = self.debug_recorder.latest_turn_bundle().unwrap_or_default();
                    self.timeline.push(
                        TimelineEntry::warning(format!("Agent error: {error}"))
                            .with_details(details),
                    );
                    self.debug_recorder.finish_turn(
                        "failed",
                        Some(runtime_error_kind_label(kind)),
                        Some(&error),
                    );
                }
                self.thinking_action_name = None;
                self.current_turn_has_thinking_entry = false;
                self.active_turn_kind = None;
                self.active_turn_title = None;
                self.dispatch_next_queued();
                self.scroll_offset = u16::MAX;
            }
        }
    }

    fn finalize_plan_response(&mut self) {
        let Some(entry) = self
            .timeline
            .iter_mut()
            .rev()
            .find(|entry| entry.actor == Actor::Assistant && entry.kind == EntryKind::Message)
        else {
            return;
        };

        let Some((title, body)) = extract_plan_title_and_body(&entry.body) else {
            return;
        };

        self.thinking_action_name = extract_plan_action_names(&body).first().cloned();
        entry.title = Some(title);
        entry.body = body;
    }

    pub(super) fn streaming_title_for_turn(&self, kind: TurnKind) -> Option<String> {
        match kind {
            TurnKind::Plan => None,
            TurnKind::Chat => self.latest_plan_title(),
        }
    }

    fn latest_plan_title(&self) -> Option<String> {
        self.timeline
            .iter()
            .rev()
            .find_map(|entry| (entry.actor == Actor::Assistant).then(|| entry.title.clone()))
            .flatten()
    }

    fn current_turn_id(&self) -> Option<&str> {
        match &self.agent_state.turn_state {
            crate::agent::state::TurnState::Streaming { turn_id } => Some(turn_id.as_str()),
            _ => None,
        }
    }
}

fn stable_fallback_action_name(text: &str) -> Option<String> {
    const FILLER: &[&str] = &[
        "next", "step", "then", "will", "would", "should", "i", "we", "to", "the", "a", "an",
        "and", "now",
    ];

    let tokens = text.split_whitespace().collect::<Vec<_>>();
    for (index, raw_token) in tokens.iter().enumerate() {
        let trimmed = raw_token
            .trim_matches(|c: char| {
                matches!(
                    c,
                    ',' | '.'
                        | '!'
                        | '?'
                        | ';'
                        | ':'
                        | '('
                        | ')'
                        | '['
                        | ']'
                        | '"'
                        | '\''
                        | '`'
                        | '*'
                        | '-'
                )
            })
            .trim();

        if trimmed.is_empty() || trimmed.chars().all(|c| c.is_ascii_digit()) {
            continue;
        }

        let lowered = trimmed.to_ascii_lowercase();
        if FILLER.iter().any(|filler| *filler == lowered) {
            continue;
        }

        let has_boundary_after_token = index + 1 < tokens.len() || trimmed.len() != raw_token.len();
        if has_boundary_after_token {
            return short_action_name_from_text(trimmed);
        }

        return None;
    }

    None
}

pub(super) fn turn_failed_app_log_message(kind: RuntimeErrorKind, turn_id: Option<&str>) -> String {
    match turn_id {
        Some(turn_id) => format!(
            "tick: TurnFailed kind={} turn_id={turn_id} details=redacted",
            runtime_error_kind_label(kind)
        ),
        None => format!(
            "tick: TurnFailed kind={} details=redacted",
            runtime_error_kind_label(kind)
        ),
    }
}

fn runtime_error_kind_label(kind: RuntimeErrorKind) -> &'static str {
    match kind {
        RuntimeErrorKind::ProviderTransient => "ProviderTransient",
        RuntimeErrorKind::ProviderFatal => "ProviderFatal",
        RuntimeErrorKind::ProtocolInvalidPayload => "ProtocolInvalidPayload",
        RuntimeErrorKind::ToolExecution => "ToolExecution",
        RuntimeErrorKind::Cancelled => "Cancelled",
    }
}

fn structured_debug_context<'a>(event: &'a DebugEventSnapshot) -> StructuredEventContext<'a> {
    StructuredEventContext {
        turn_id: event.turn_id.as_deref(),
        tool_name: event.tool_name.as_deref(),
        error_kind: event.error_kind.as_deref(),
        call_id: event.call_id.as_deref(),
        session_id: Some(event.session_id.as_str()),
        workspace_path: Some(event.workspace_path.as_str()),
        queue_depth: Some(event.queue_depth),
        event_seq: event.event_seq,
        turn_kind: event.turn_kind.as_deref(),
        ..StructuredEventContext::default()
    }
}

fn append_tool_debug_details(details: String, event: &DebugEventSnapshot) -> String {
    let mut lines = Vec::new();
    if !details.is_empty() {
        lines.push(details);
    }
    if let Some(turn_id) = event.turn_id.as_deref() {
        lines.push(format!("debug.turn_id={turn_id}"));
    }
    if let Some(call_id) = event.call_id.as_deref() {
        lines.push(format!("debug.call_id={call_id}"));
    }
    if let Some(event_seq) = event.event_seq {
        lines.push(format!("debug.event_seq={event_seq}"));
    }
    lines.join("\n")
}

//! Pure utility functions used by `ChatApp` and its submodules.

/// Shorten `/home/<user>/...` to `~/...` for display.
pub(crate) fn shorten_home(path: &str) -> String {
    if let Ok(home) = std::env::var("HOME")
        && let Some(rest) = path.strip_prefix(&home)
    {
        return format!("~{rest}");
    }
    path.to_owned()
}

pub(crate) fn normalize_slash_query(query: &str) -> String {
    query
        .replace(['\r', '\n'], " ")
        .split_whitespace()
        .collect::<Vec<_>>()
        .join(" ")
}

pub(super) fn infer_pr_label_from_branch(branch: &str) -> Option<String> {
    let branch = branch.trim();
    if branch.is_empty() {
        return None;
    }

    let segments = branch
        .split('/')
        .filter(|segment| !segment.is_empty())
        .collect::<Vec<_>>();

    for (index, segment) in segments.iter().enumerate() {
        if let Some(number) = segment.strip_prefix("pr-").and_then(leading_digits) {
            return Some(format!("PR#{number}"));
        }
        if let Some(number) = segment.strip_prefix("pr_").and_then(leading_digits) {
            return Some(format!("PR#{number}"));
        }
        if matches!(*segment, "pr" | "pull")
            && let Some(number) = segments
                .get(index + 1)
                .and_then(|next| leading_digits(next))
        {
            return Some(format!("PR#{number}"));
        }
    }

    let hash_suffix = branch.rsplit_once('#').map(|(_, suffix)| suffix)?;
    let number = leading_digits(hash_suffix)?;
    Some(format!("PR#{number}"))
}

fn leading_digits(value: &str) -> Option<&str> {
    let end = value
        .char_indices()
        .find_map(|(index, ch)| (!ch.is_ascii_digit()).then_some(index))
        .unwrap_or(value.len());
    (end > 0).then_some(&value[..end])
}

pub(super) fn parse_workspace_claim_path(claim: &str) -> Option<&str> {
    let (resource, _) = claim.split_once('#')?;
    let path = resource.strip_prefix("fs:")?;
    (!path.is_empty()).then_some(path)
}

pub(super) fn preview_text(text: &str, max_chars: usize) -> &str {
    if text.chars().count() <= max_chars {
        return text;
    }

    let end = text
        .char_indices()
        .nth(max_chars)
        .map(|(index, _)| index)
        .unwrap_or(text.len());

    &text[..end]
}

pub(super) fn summarize_tool_arguments(arguments: &str) -> String {
    preview_text(arguments, 60).to_owned()
}

pub(super) fn summarize_tool_output(output: &str) -> String {
    let first_line = output.lines().next().unwrap_or("");
    preview_text(first_line, 80).to_owned()
}

/// Detect the current git branch. Returns empty string if not in a git repo.
pub(super) fn detect_branch(repo_path: &str) -> String {
    std::process::Command::new("git")
        .args(["rev-parse", "--abbrev-ref", "HEAD"])
        .current_dir(repo_path)
        .output()
        .ok()
        .and_then(|o| {
            if o.status.success() {
                String::from_utf8(o.stdout)
                    .ok()
                    .map(|s| s.trim().to_owned())
            } else {
                None
            }
        })
        .unwrap_or_default()
}

//! Background model-metadata refresh subsystem.
//!
//! Periodically fetches the provider's model list and config on a background
//! thread so the UI can display context-length limits and populate the model
//! picker without blocking the event loop.

use std::path::Path;
use std::sync::Arc;
use std::sync::mpsc::{Receiver, Sender};
use std::time::{Duration, Instant};

use crate::provider::{ModelInfo, ProviderConfigPort};

#[derive(Debug, Clone)]
pub(super) struct ModelMetadataRefreshResult {
    pub(super) request_id: u64,
    pub(super) available_models: Vec<ModelInfo>,
    pub(super) config_max_tokens: Option<u32>,
}

pub(crate) struct ModelMetadataState {
    pub(super) available_models: Vec<ModelInfo>,
    pub(super) model_context_max_tokens: Option<u32>,
    pub(super) config_max_tokens: Option<u32>,
    provider_config: Arc<dyn ProviderConfigPort>,
    tx: Sender<ModelMetadataRefreshResult>,
    rx: Receiver<ModelMetadataRefreshResult>,
    handle: Option<std::thread::JoinHandle<()>>,
    stalled_handle: Option<std::thread::JoinHandle<()>>,
    pub(super) retry_exhausted: bool,
    in_flight: bool,
    pub(super) interval: Duration,
    pub(super) timeout: Duration,
    active_request_id: u64,
    last_refresh_at: Instant,
    started_at: Option<Instant>,
}

impl ModelMetadataState {
    pub(super) fn new(
        config_max_tokens: Option<u32>,
        provider_config: Arc<dyn ProviderConfigPort>,
    ) -> Self {
        let (tx, rx) = std::sync::mpsc::channel();
        Self {
            available_models: Vec::new(),
            model_context_max_tokens: None,
            config_max_tokens,
            provider_config,
            tx,
            rx,
            handle: None,
            stalled_handle: None,
            retry_exhausted: false,
            in_flight: false,
            interval: Duration::from_secs(300),
            timeout: Duration::from_secs(30),
            active_request_id: 0,
            last_refresh_at: Instant::now(),
            started_at: None,
        }
    }

    /// Called after the active model changes — refreshes cached limits and
    /// schedules a background fetch for fresh data.
    pub(super) fn on_model_changed(&mut self, workspace_root: &Path, model_name: &str) {
        let repo_root = workspace_root.to_string_lossy();
        self.config_max_tokens = self.provider_config.configured_max_tokens(&repo_root);
        self.model_context_max_tokens = self
            .provider_config
            .resolve_model_context_length(&self.available_models, model_name);
        self.schedule_refresh(workspace_root);
    }

    /// Per-tick driver: detects stale/timed-out refreshes and applies results.
    pub(super) fn tick(&mut self, workspace_root: &Path, model_name: &str) {
        self.expire_stale_refresh();
        self.apply_completed(model_name);

        if !self.in_flight && self.last_refresh_at.elapsed() >= self.interval {
            self.schedule_refresh(workspace_root);
        }
    }

    /// Resolved context-length limit: provider model limit or config override.
    pub(super) fn resolved_context_limit(&self) -> Option<u32> {
        self.model_context_max_tokens.or(self.config_max_tokens)
    }

    /// Live-fetch available models through the provider config port.
    pub(super) fn fetch_available_models(&self, repo_root: &str) -> Vec<ModelInfo> {
        self.provider_config.available_models(repo_root)
    }

    // ── private ─────────────────────────────────────────────────────

    fn schedule_refresh(&mut self, workspace_root: &Path) {
        if self.in_flight {
            return;
        }

        if self
            .stalled_handle
            .as_ref()
            .is_some_and(std::thread::JoinHandle::is_finished)
        {
            self.stalled_handle = None;
            self.retry_exhausted = false;
        }

        if self.stalled_handle.is_some() && self.retry_exhausted {
            return;
        }

        self.active_request_id = self.active_request_id.wrapping_add(1);
        self.in_flight = true;
        self.started_at = Some(Instant::now());
        let request_id = self.active_request_id;
        let tx = self.tx.clone();
        let repo_root = workspace_root.to_string_lossy().into_owned();
        #[cfg(test)]
        let available_models_behavior =
            crate::provider::current_available_models_behavior_for_test();
        self.handle = Some(std::thread::spawn(move || {
            #[cfg(test)]
            let _available_models_behavior =
                crate::provider::set_available_models_behavior_for_current_thread_for_test(
                    available_models_behavior,
                );
            let result = ModelMetadataRefreshResult {
                request_id,
                available_models: crate::provider::available_models(&repo_root),
                config_max_tokens: crate::provider::configured_max_tokens(&repo_root),
            };
            let _ = tx.send(result);
        }));
    }

    fn expire_stale_refresh(&mut self) {
        if !self.in_flight
            || self
                .started_at
                .is_none_or(|started_at| started_at.elapsed() < self.timeout)
        {
            return;
        }

        if self
            .handle
            .as_ref()
            .is_some_and(std::thread::JoinHandle::is_finished)
        {
            self.handle = None;
            self.in_flight = false;
            self.started_at = None;
        } else if self
            .stalled_handle
            .as_ref()
            .is_some_and(|h| !h.is_finished())
        {
            self.handle = None;
            self.in_flight = false;
            self.started_at = None;
            self.retry_exhausted = true;
            self.active_request_id = self.active_request_id.wrapping_add(1);
            self.last_refresh_at = Instant::now();
        } else {
            self.stalled_handle = self.handle.take();
            self.in_flight = false;
            self.started_at = None;
        }
    }

    fn apply_completed(&mut self, model_name: &str) {
        while let Ok(result) = self.rx.try_recv() {
            if result.request_id != self.active_request_id {
                continue;
            }
            self.available_models = result.available_models;
            self.config_max_tokens = result.config_max_tokens;
            self.model_context_max_tokens = self
                .provider_config
                .resolve_model_context_length(&self.available_models, model_name);
            self.handle = None;
            self.in_flight = false;
            self.started_at = None;
            self.retry_exhausted = false;
            self.last_refresh_at = Instant::now();
        }
    }
}

#[cfg(test)]
impl ModelMetadataState {
    /// Expose `in_flight` for testing early-return in `schedule_refresh`.
    pub(super) fn set_in_flight_for_test(&mut self, value: bool) {
        self.in_flight = value;
    }

    /// Install a finished (already-joined) stalled handle.
    pub(super) fn set_stalled_handle_finished_for_test(&mut self) {
        self.stalled_handle = Some(std::thread::spawn(|| {}));
        // Spin briefly until the spawned thread completes.
        while !self.stalled_handle.as_ref().unwrap().is_finished() {
            std::thread::sleep(Duration::from_millis(1));
        }
    }

    /// Install a long-running stalled handle that won't finish during the test.
    pub(super) fn set_stalled_handle_running_for_test(&mut self) {
        self.stalled_handle = Some(std::thread::spawn(|| {
            std::thread::sleep(Duration::from_secs(30));
        }));
    }

    /// Force the refresh into a timed-out state by back-dating `started_at`.
    pub(super) fn force_timeout_for_test(&mut self) {
        self.in_flight = true;
        self.started_at = Some(Instant::now() - self.timeout - Duration::from_millis(10));
        // Install a long-running handle so `expire_stale_refresh` doesn't
        // short-circuit on a finished handle.
        self.handle = Some(std::thread::spawn(|| {
            std::thread::sleep(Duration::from_secs(30));
        }));
    }

    /// Inject a result with a specific `request_id` into the channel so
    /// `apply_completed` can observe a mismatched id.
    pub(super) fn inject_result_for_test(&self, request_id: u64) {
        let _ = self.tx.send(ModelMetadataRefreshResult {
            request_id,
            available_models: vec![],
            config_max_tokens: None,
        });
    }

    /// Current active request id for assertions.
    pub(super) fn active_request_id_for_test(&self) -> u64 {
        self.active_request_id
    }

    pub(super) fn in_flight_for_test(&self) -> bool {
        self.in_flight
    }

    pub(super) fn has_stalled_handle_for_test(&self) -> bool {
        self.stalled_handle.is_some()
    }
}

use super::*;

impl ChatApp {
    pub fn send_message(&mut self, input: &str) {
        self.send_message_internal(input, true);
    }

    pub(crate) fn send_message_without_command_dispatch(&mut self, input: &str) {
        self.send_message_internal(input, false);
    }

    pub(crate) fn execute_discover_agents_command(&mut self) {
        self.push_user_message("/discover-agents");
        self.refresh_acp_agents();
    }

    fn send_message_internal(&mut self, input: &str, allow_command_dispatch: bool) {
        let trimmed = input.trim();
        if trimmed.is_empty() {
            return;
        }

        if allow_command_dispatch
            && !self.agent_state.is_busy()
            && trimmed != "/plan"
            && self.command_registry.find(trimmed).is_some()
        {
            if let Err(err) = self.execute_palette_command_sync(trimmed, serde_json::json!({})) {
                self.timeline
                    .push(TimelineEntry::warning(format!("Command failed: {err}")));
                self.scroll_offset = u16::MAX;
            }
            return;
        }

        let turn = build_pending_turn_for_mode(trimmed, self.user_mode);

        info!(
            "send_message: len={} preview={:.60}",
            trimmed.len(),
            trimmed
        );

        // Trigger demo playback when user types "1"
        if trimmed == "1" {
            self.timeline.clear();
            self.demo_queue = crate::chat::demo::demo_playback_script();
            self.demo_last_add = None;
            self.scroll_offset = u16::MAX;
            return;
        }

        self.has_user_sent = true;

        // Admission control: queue if agent is busy instead of dropping
        if self.agent_state.is_busy() {
            info!(
                "send_message: queued (agent busy) queue_depth={}",
                self.pending_messages.len() + 1
            );
            self.pending_messages.push_back(turn);
            return;
        }

        if !self.dispatch_turn(turn) {
            self.dispatch_next_queued();
        }
    }

    fn push_user_message(&mut self, body: &str) {
        self.messages.push(ChatMessage {
            author: Author::User,
            body: body.to_owned(),
        });

        self.has_user_sent = true;
        self.timeline
            .push(TimelineEntry::user_message(body.to_owned()));
    }

    pub(super) fn refresh_acp_agents(&mut self) -> bool {
        self.timeline
            .push(TimelineEntry::hint("Discovering ACP agents..."));
        self.scroll_offset = u16::MAX;

        if let Err(error) = self.agent_runtime.refresh_acp_agents() {
            warn!("refresh_acp_agents: failed to enqueue refresh: {error}");
            self.timeline.push(TimelineEntry::warning(format!(
                "Failed to refresh ACP agents: {error}"
            )));
            self.scroll_offset = u16::MAX;
            return false;
        }

        true
    }

    pub(super) fn dispatch_turn(&mut self, mut turn: PendingTurn) -> bool {
        if !turn.timeline_inserted {
            self.messages.push(ChatMessage {
                author: Author::User,
                body: turn.user_text.clone(),
            });
            self.timeline
                .push(TimelineEntry::user_message(turn.user_text.clone()));
            turn.timeline_inserted = true;
        }

        let dispatched = match turn.dispatch {
            PendingDispatch::Runtime {
                runtime_prompt,
                kind,
            } => {
                self.active_turn_kind = Some(kind);
                self.active_turn_title = self.streaming_title_for_turn(kind);
                if let Err(e) = self.agent_runtime.submit_turn(&runtime_prompt) {
                    warn!("dispatch_turn: submit_turn failed: {e}");
                    self.active_turn_kind = None;
                    self.active_turn_title = None;
                    self.timeline
                        .push(TimelineEntry::warning(format!("Runtime error: {e}")));
                    self.scroll_offset = u16::MAX;
                    return false;
                }
                true
            }
            PendingDispatch::DiscoverAgents => self.refresh_acp_agents(),
        };

        self.scroll_offset = u16::MAX;
        dispatched
    }

    /// Dispatches the next queued message to the agent runtime (FIFO).
    /// Called after any terminal turn event (TurnComplete, TurnFailed).
    pub(super) fn dispatch_next_queued(&mut self) {
        while let Some(turn) = self.pending_messages.pop_front() {
            info!(
                "dispatch_next_queued: dispatching len={} remaining={}",
                turn.user_text.len(),
                self.pending_messages.len()
            );
            if self.dispatch_turn(turn) {
                break;
            }
        }
    }
}

#[cfg(test)]
pub(super) fn build_pending_turn(input: &str) -> PendingTurn {
    build_pending_turn_for_mode(input, UserMode::Auto)
}

pub(super) fn build_pending_turn_for_mode(input: &str, user_mode: UserMode) -> PendingTurn {
    let trimmed = input.trim();
    if trimmed == "/discover-agents" {
        return PendingTurn {
            user_text: trimmed.to_owned(),
            dispatch: PendingDispatch::DiscoverAgents,
            timeline_inserted: false,
        };
    }

    if let Some(request) = trimmed.strip_prefix("/plan") {
        return PendingTurn {
            user_text: trimmed.to_owned(),
            dispatch: PendingDispatch::Runtime {
                runtime_prompt: build_plan_prompt(request.trim()),
                kind: TurnKind::Plan,
            },
            timeline_inserted: false,
        };
    }

    if user_mode == UserMode::Plan {
        return PendingTurn {
            user_text: trimmed.to_owned(),
            dispatch: PendingDispatch::Runtime {
                runtime_prompt: build_plan_prompt(trimmed),
                kind: TurnKind::Plan,
            },
            timeline_inserted: false,
        };
    }

    PendingTurn {
        user_text: trimmed.to_owned(),
        dispatch: PendingDispatch::Runtime {
            runtime_prompt: trimmed.to_owned(),
            kind: TurnKind::Chat,
        },
        timeline_inserted: false,
    }
}

fn build_plan_prompt(request: &str) -> String {
    format!(
        "You are in planning mode.\n\
         Generate a concise implementation plan only.\n\
         First line must be a short plain-text title with no markdown, no numbering, and no label.\n\
         After a blank line, write the plan body as concise ordered steps.\n\
         Keep the answer focused on planning.\n\n\
         User request:\n{request}"
    )
}

pub(super) fn extract_plan_title_and_body(text: &str) -> Option<(String, String)> {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return None;
    }

    let mut lines = trimmed.lines();
    let title = lines.next()?.trim().trim_matches('#').trim().to_owned();
    if title.is_empty() {
        return None;
    }

    let body = lines.collect::<Vec<_>>().join("\n").trim().to_owned();
    Some((title, body))
}

pub(super) fn short_action_name_from_text(text: &str) -> Option<String> {
    let action = first_action_word(text)?;
    Some(truncate_action_name(action, 10))
}

pub(super) fn extract_plan_action_names(body: &str) -> Vec<String> {
    let trimmed = body.trim();
    if trimmed.is_empty() {
        return Vec::new();
    }

    if let Some(name) = parse_next_step_name_line(trimmed) {
        return vec![name];
    }

    let mut names = Vec::new();
    for line in trimmed.lines() {
        if let Some(candidate) = parse_numbered_plan_action_line(line)
            && let Some(name) = short_action_name_from_text(&candidate)
        {
            names.push(name);
        }
    }

    if names.is_empty()
        && let Some(name) = short_action_name_from_text(trimmed)
    {
        names.push(name);
    }

    names
}

pub(super) fn parse_next_step_name_line(text: &str) -> Option<String> {
    let first_line = text.lines().next()?.trim();
    let value = first_line.strip_prefix("next_step_name:")?.trim();
    short_action_name_from_text(value)
}

fn parse_numbered_plan_action_line(line: &str) -> Option<String> {
    let trimmed = line.trim();
    if trimmed.is_empty() {
        return None;
    }

    let candidate = trimmed
        .trim_start_matches(|c: char| {
            c.is_ascii_digit() || matches!(c, '.' | ')' | ':' | '-' | '•' | '[' | ']' | ' ')
        })
        .trim_start();

    if candidate.is_empty() || candidate == trimmed {
        return None;
    }

    Some(candidate.to_owned())
}

fn first_action_word(text: &str) -> Option<&str> {
    const FILLER: &[&str] = &[
        "next", "step", "then", "will", "would", "should", "i", "we", "to", "the", "a", "an",
        "and", "now",
    ];

    text.split_whitespace().find_map(|token| {
        let token = token
            .trim_matches(|c: char| {
                matches!(
                    c,
                    ',' | '.'
                        | '!'
                        | '?'
                        | ';'
                        | ':'
                        | '('
                        | ')'
                        | '['
                        | ']'
                        | '"'
                        | '\''
                        | '`'
                        | '*'
                        | '-'
                )
            })
            .trim();

        if token.is_empty() || token.chars().all(|c| c.is_ascii_digit()) {
            return None;
        }

        let lowered = token.to_ascii_lowercase();
        if FILLER.iter().any(|f| *f == lowered) {
            None
        } else {
            Some(token)
        }
    })
}

fn truncate_action_name(name: &str, max_chars: usize) -> String {
    let mut chars = name.chars();
    let mut shortened = String::new();
    for _ in 0..max_chars {
        if let Some(ch) = chars.next() {
            shortened.push(ch);
        } else {
            return shortened.to_ascii_lowercase();
        }
    }

    if chars.next().is_some() {
        shortened.push('…');
    }

    shortened.to_ascii_lowercase()
}

pub(super) fn format_tool_call_details(
    arguments: &str,
    batch_id: u32,
    replay_index: usize,
    normalized_claims: &[String],
) -> String {
    let claims = if normalized_claims.is_empty() {
        "<none>".to_owned()
    } else {
        let mut sorted_claims = normalized_claims.to_vec();
        sorted_claims.sort();
        sorted_claims.join(",")
    };
    let metadata_line =
        format!("batch_id={batch_id} replay_index={replay_index} normalized_claims={claims}");

    if arguments.is_empty() {
        metadata_line
    } else {
        format!("{arguments}\n{metadata_line}")
    }
}

pub(crate) fn tool_call_details_payload(details: &str) -> &str {
    let mut cutoff = details.len();
    for marker in ["\ndebug.", "\nbatch_id="] {
        if let Some(index) = details.find(marker) {
            cutoff = cutoff.min(index);
        }
    }

    details[..cutoff].trim_end_matches('\n')
}

pub(super) fn extract_tool_call_metadata_line(details: &str) -> Option<String> {
    tool_call_metadata_line(details).map(ToOwned::to_owned)
}

pub(crate) fn tool_call_metadata_line(details: &str) -> Option<&str> {
    details.lines().rev().find(|line| {
        line.starts_with("batch_id=")
            && line.contains(" replay_index=")
            && line.contains(" normalized_claims=")
    })
}

