            workspace_root,
            model_name,
            model_metadata: ModelMetadataState::new(config_max_tokens, provider_config),
            git_pr_label,
            user_mode: UserMode::Auto,
            // All remaining fields are zero/empty/false/None defaults.
            should_quit: false,
            show_details: false,
            tick_count: 0,
            demo_queue: Vec::new(),
            demo_last_add: None,
