//! Modal picker overlay — a bottom-anchored selection list.
//! Used for `/` command palette, confirmation dialogs, and setup wizards.

use tui_overlay::OverlayState;
use tui_widget_list::ListState;

pub const PICKER_PAGE_SIZE: usize = 6;

/// What the picker is currently selecting.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PickerContext {
    Commands,
    ThemeSelect,
    ModelSelect,
}

#[derive(Debug, Clone)]
pub struct PickerItem {
    pub label: String,
    pub description: String,
}

impl PickerItem {
    pub fn new(label: impl Into<String>, description: impl Into<String>) -> Self {
        Self {
            label: label.into(),
            description: description.into(),
        }
    }
}

#[derive(Debug, Clone)]
pub struct ModalPicker {
    pub title: String,
    pub items: Vec<PickerItem>,
    pub filter: String,
    pub context: PickerContext,
    overlay_state: OverlayState,
    list_state: ListState,
}

impl ModalPicker {
    pub fn new(title: impl Into<String>, items: Vec<PickerItem>) -> Self {
        Self::with_context(title, items, PickerContext::Commands)
    }

    pub fn with_context(
        title: impl Into<String>,
        items: Vec<PickerItem>,
        context: PickerContext,
    ) -> Self {
        Self {
            title: title.into(),
            items,
            filter: String::new(),
            context,
            overlay_state: OverlayState::new(),
            list_state: ListState::default(),
        }
    }

    pub fn command_palette_from_registry(
        registry: &crate::chat::commands::CommandRegistry,
    ) -> Self {
        let items = registry
            .list()
            .into_iter()
            .map(|spec| PickerItem::new(spec.name.clone(), spec.description.clone()))
            .collect();
        Self::with_context("Commands", items, PickerContext::Commands)
    }

    pub fn open(&mut self) {
        self.overlay_state.open();
        self.filter.clear();
        self.reset_selection();
    }

    pub fn close(&mut self) {
        self.overlay_state.close();
        self.filter.clear();
    }

    pub fn is_visible(&self) -> bool {
        self.overlay_state.is_open() || self.overlay_state.is_animating()
    }

    pub fn is_open(&self) -> bool {
        self.overlay_state.is_open()
    }

    pub fn overlay_state(&self) -> &OverlayState {
        &self.overlay_state
    }

    pub fn overlay_state_mut(&mut self) -> &mut OverlayState {
        &mut self.overlay_state
    }

    pub fn list_state(&self) -> &ListState {
        &self.list_state
    }

    pub fn list_state_mut(&mut self) -> &mut ListState {
        &mut self.list_state
    }

    pub fn selected_index(&self) -> Option<usize> {
        self.list_state.selected
    }

    pub fn move_up(&mut self) {
        let count = self.filtered_items().len();
        if count == 0 {
            self.list_state.select(None);
            return;
        }
        let current = self
            .list_state
            .selected
            .unwrap_or(0)
            .min(count.saturating_sub(1));
        let next = current.checked_sub(1).unwrap_or(count - 1);
        self.list_state.select(Some(next));
    }

    pub fn move_down(&mut self) {
        let count = self.filtered_items().len();
        if count == 0 {
            self.list_state.select(None);
            return;
        }
        let current = self
            .list_state
            .selected
            .unwrap_or(0)
            .min(count.saturating_sub(1));
        let next = (current + 1) % count;
        self.list_state.select(Some(next));
    }

    pub fn select_current(&self) -> Option<String> {
        let filtered = self.filtered_items();
        let index = self
            .list_state
            .selected
            .map(|selected| selected.min(filtered.len().saturating_sub(1)))?;
        filtered.get(index).map(|item| item.label.clone())
    }

    pub fn push_filter(&mut self, ch: char) {
        if self.context == PickerContext::Commands && self.filter.is_empty() && ch != '/' {
            self.filter.push('/');
        }
        self.filter.push(ch);
        self.reset_selection();
    }

    pub fn pop_filter(&mut self) {
        self.filter.pop();
        self.reset_selection();
    }

    /// Returns the slice of filtered items visible in the current scroll window.
    pub fn visible_window(&self) -> (Vec<&PickerItem>, usize) {
        let filtered = self.filtered_items();
        let offset = self.window_offset(filtered.len());
        let end = (offset + PICKER_PAGE_SIZE).min(filtered.len());
        let window: Vec<&PickerItem> = filtered[offset..end].to_vec();
        (window, offset)
    }

    pub fn has_scroll_up(&self) -> bool {
        let count = self.filtered_items().len();
        self.window_offset(count) > 0
    }

    pub fn has_scroll_down(&self) -> bool {
        let count = self.filtered_items().len();
        let offset = self.window_offset(count);
        offset + PICKER_PAGE_SIZE < count
    }

    pub fn filtered_items(&self) -> Vec<&PickerItem> {
        if self.context != PickerContext::Commands {
            if self.filter.is_empty() {
                return self.items.iter().collect();
            }

            let filter = self.filter.to_lowercase();
            return self
                .items
                .iter()
                .filter(|item| {
                    item.label.to_lowercase().contains(&filter)
                        || item.description.to_lowercase().contains(&filter)
                })
                .collect();
        }

        let filter = self.filter.trim();
        if filter.is_empty() {
            return self.items.iter().collect();
        }
        if !filter.starts_with('/') {
            return Vec::new();
        }

        let specs: Vec<crate::chat::commands::CommandSpec> = self
            .items
            .iter()
            .map(|item| crate::chat::commands::CommandSpec {
                name: item.label.clone(),
                description: item.description.clone(),
                args_schema: serde_json::json!({ "type": "object" }),
            })
            .collect();

        let ordered_names = crate::chat::commands::matcher::ranked_match_names(filter, &specs);
        ordered_names
            .into_iter()
            .filter_map(|name| self.items.iter().find(|item| item.label == name))
            .collect()
    }

    fn reset_selection(&mut self) {
        if self.filtered_items().is_empty() {
            self.list_state.select(None);
        } else {
            self.list_state.select(Some(0));
        }
    }

    fn window_offset(&self, count: usize) -> usize {
        let selected = self
            .list_state
            .selected
            .unwrap_or(0)
            .min(count.saturating_sub(1));
        if selected >= PICKER_PAGE_SIZE {
            selected + 1 - PICKER_PAGE_SIZE
        } else {
            0
        }
    }
}

