        let mut picker = ModalPicker::new("Commands", vec![PickerItem::new("/help", "help")]);
        assert!(!picker.is_visible());

        picker.open();
        assert!(picker.is_visible());

        picker.close();
        assert!(!picker.is_visible());
    }

    #[test]
    fn filter_updates_reset_selection() {
        let mut picker = command_palette_for_test();
        picker.open();
        picker.move_down();
        assert_eq!(picker.selected_index(), Some(1));

        picker.push_filter('p');
        assert_eq!(picker.filter, "/p");
        assert_eq!(picker.selected_index(), Some(0));
    }

    #[test]
    fn command_palette_includes_plan_command() {
        let picker = command_palette_for_test();
        let commands: Vec<&str> = picker
            .items
            .iter()
            .map(|item| item.label.as_str())
            .collect();

        assert!(
            commands.contains(&"/plan"),
            "command palette should expose /plan"
        );
    }

    #[test]
    fn command_palette_includes_discover_agents_command() {
        let picker = command_palette_for_test();
        let commands: Vec<&str> = picker
            .items
            .iter()
            .map(|item| item.label.as_str())
            .collect();

        assert!(
            commands.contains(&"/discover-agents"),
            "command palette should expose /discover-agents"
        );
    }

    #[test]
    fn selected_item_empty_picker() {
        let picker = ModalPicker::new("Empty", vec![]);
        assert!(picker.select_current().is_none());
        assert!(picker.selected_index().is_none());
    }

    #[test]
    fn list_state_accessors() {
        let mut picker = ModalPicker::new("Test", vec![PickerItem::new("a", "desc")]);
        // Read-only accessor returns default state
        let _ = picker.list_state();
        // Mutable accessor allows selection changes
        picker.list_state_mut().select(Some(0));
        assert_eq!(picker.selected_index(), Some(0));
    }

    #[test]
    fn move_up_on_empty_picker_is_noop() {
        let mut picker = ModalPicker::new("Empty", vec![]);
        picker.move_up();
        assert_eq!(picker.selected_index(), None);
    }

    #[test]
    fn move_down_on_empty_picker_is_noop() {
        let mut picker = ModalPicker::new("Empty", vec![]);
        picker.move_down();
        assert_eq!(picker.selected_index(), None);
    }

    #[test]
    fn move_up_at_top_wraps_to_bottom() {
        let items = vec![
            PickerItem::new("a", "first"),
            PickerItem::new("b", "second"),
        ];
        let mut picker =
            ModalPicker::with_context("Test", items, super::PickerContext::ThemeSelect);
        picker.open();
        // Selection starts at 0 after open
        assert_eq!(picker.selected_index(), Some(0));
        // move_up from 0 wraps to last item
        picker.move_up();
        assert_eq!(picker.selected_index(), Some(1));
    }

    #[test]
    fn move_down_at_bottom_wraps_to_top() {
        let items = vec![
            PickerItem::new("a", "first"),
            PickerItem::new("b", "second"),
        ];
        let mut picker =
            ModalPicker::with_context("Test", items, super::PickerContext::ThemeSelect);
        picker.open();
        picker.move_down(); // 0 -> 1
        assert_eq!(picker.selected_index(), Some(1));
        picker.move_down(); // 1 -> 0 (wraps)
        assert_eq!(picker.selected_index(), Some(0));
    }

    #[test]
    fn visible_window_with_many_items() {
        let items: Vec<PickerItem> = (0..20)
            .map(|i| PickerItem::new(format!("item-{i}"), format!("desc-{i}")))
            .collect();
        let mut picker = ModalPicker::with_context("Big", items, super::PickerContext::ThemeSelect);
        picker.open();

        // Initially at index 0 — window starts at offset 0
        let (window, offset) = picker.visible_window();
        assert_eq!(offset, 0);
        assert_eq!(window.len(), super::PICKER_PAGE_SIZE);
        assert_eq!(window[0].label, "item-0");

        assert!(!picker.has_scroll_up());
        assert!(picker.has_scroll_down());

        // Navigate past page size to trigger scroll
        for _ in 0..super::PICKER_PAGE_SIZE + 2 {
            picker.move_down();
        }
        let (window, offset) = picker.visible_window();
        assert!(offset > 0, "should have scrolled");
        assert_eq!(window.len(), super::PICKER_PAGE_SIZE);

        assert!(picker.has_scroll_up());
    }
}

use crate::agent::protocol::AgentEvent;

/// Runtime boundary trait used by chat to interact with the agent runtime.
/// Keeps a minimal, testable surface so the runtime can be swapped or mocked.
pub trait AgentRuntimePort {
    /// Submit a new turn to the runtime.
    fn submit_turn(&self, prompt: &str) -> Result<(), String>;

    /// Switch the active model.
    fn set_model(&self, model: &str) -> Result<(), String>;

    /// Refresh ACP-discovered agents and rebuild tool registry.
    fn refresh_acp_agents(&self) -> Result<(), String>;

    /// Cancel the current turn.
    fn cancel(&self);

    /// Non-blocking poll for the next event.
    fn try_recv(&self) -> Option<AgentEvent>;

    /// Test-only: shutdown runtime and join worker thread.
    #[cfg(test)]
    fn shutdown_for_test(&mut self);
}

use std::path::Path;

/// A lightweight, read-oriented snapshot of the current session state.
#[derive(Debug, Clone, Default)]
pub struct SessionSummary {
    pub session_label: String,
    pub cwd: String,
    pub active_intent: String,
    pub plan_status: String,
    pub checkpoints: Vec<String>,
    pub ready_todos: usize,
    pub in_progress_todos: usize,
    pub done_todos: usize,
}

impl SessionSummary {
    /// Loads live session state.
    ///
    /// Derives the session directory from the `COPILOT_AGENT_SESSION_ID`
    /// environment variable (`~/.copilot/session-state/<id>`).  If the env
    /// var is absent or the directory does not exist, returns an intentionally
    /// empty summary rather than bogus placeholder data.
    pub fn load(repo_path: &Path) -> Self {
        let session_dir = std::env::var("COPILOT_AGENT_SESSION_ID").ok().map(|id| {
            let home = std::env::var("HOME").unwrap_or_default();
            std::path::PathBuf::from(home)
                .join(".copilot/session-state")
                .join(id)
        });
        Self::load_from_dir(repo_path, session_dir.as_deref())
    }

    /// Loads live session state from a specific `session_dir`.
    ///
    /// Exposed as `pub` so tests can supply a deterministic fixture directory
    /// without setting environment variables.
    pub fn load_from_dir(repo_path: &Path, session_dir: Option<&Path>) -> Self {
        let Some(dir) = session_dir else {
            return Self::default();
        };
        if !dir.exists() {
            return Self::default();
        }

        // Session label: read from workspace.yaml or fall back to dir name
        let session_label = read_yaml_field(dir.join("workspace.yaml").as_path(), "label")
            .or_else(|| dir.file_name().and_then(|n| n.to_str()).map(str::to_owned))
            .unwrap_or_default();

        // CWD from repo_path (or workspace.yaml if repo_path is just ".")
        let cwd = if repo_path == Path::new(".") {
            read_yaml_field(dir.join("workspace.yaml").as_path(), "repoPath")
                .unwrap_or_else(|| ".".to_string())
        } else {
            repo_path.display().to_string()
        };

        // Plan status
        let plan_status = if dir.join("plan.md").exists() {
            "plan.md present".to_string()
        } else {
            "No plan".to_string()
        };

        // Checkpoints from checkpoints/index.md
        let checkpoints = load_checkpoints(dir.join("checkpoints/index.md").as_path());

        // Todo counts from session.db
        let (ready_todos, in_progress_todos, done_todos) =
            load_todo_counts(dir.join("session.db").as_path());

        Self {
            session_label,
            cwd,
            active_intent: load_active_intent(dir)
                .unwrap_or_else(|| "No active intent recorded".to_string()),
            plan_status,
            checkpoints,
            ready_todos,
            in_progress_todos,
            done_todos,
        }
    }

    /// Returns a deterministic seed suitable for tests.
    pub fn for_test() -> Self {
        Self {
            session_label: "spirit-workspace-tui".to_string(),
            cwd: "/home/lx/blazar".to_string(),
            active_intent: "Implementing Sessions workspace view".to_string(),
            plan_status: "plan.md · 6 tasks · 4 done".to_string(),
            checkpoints: vec![
                "Checkpoint 004".to_string(),
                "Checkpoint 008".to_string(),
                "Checkpoint 009".to_string(),
            ],
            ready_todos: 2,
            in_progress_todos: 1,
            done_todos: 4,
        }
    }
}

/// Reads a top-level `key: value` field from a minimal YAML file.
/// Only handles simple scalar values on the same line as the key.
fn read_yaml_field(path: &Path, key: &str) -> Option<String> {
    let text = std::fs::read_to_string(path).ok()?;
    let prefix = format!("{key}:");
    for line in text.lines() {
        if let Some(rest) = line.strip_prefix(&prefix) {
            let value = rest.trim().trim_matches('"').trim_matches('\'');
            if !value.is_empty() {
                return Some(value.to_string());
            }
        }
    }
    None
}

/// Extracts checkpoint names from `checkpoints/index.md`.
/// Collects lines containing "Checkpoint" (case-sensitive) as entries.
fn load_checkpoints(index_path: &Path) -> Vec<String> {
    let Ok(text) = std::fs::read_to_string(index_path) else {
        return vec![];
    };
    text.lines()
        .filter(|l| l.contains("Checkpoint"))
        .map(|l| {
            // Strip leading list markers ("- ", "* ") and trim
            let trimmed = l.trim_start_matches([' ', '-', '*']).trim();
            // Keep up to the first colon to avoid very long lines
            trimmed
                .split_once(':')
                .map_or(trimmed, |(left, _)| left.trim())
                .to_string()
        })
        .collect()
}

/// Queries `session.db` for todo counts grouped by status.
/// Returns `(pending, in_progress, done)`.
///
/// Opens with `SQLITE_OPEN_READ_ONLY` so a missing file is never created.
fn load_todo_counts(db_path: &Path) -> (usize, usize, usize) {
    // Explicit existence check: read-only open still fails gracefully on most
    // systems for a missing file, but the guard makes the intent unambiguous and
    // prevents any edge-case where the SQLite VFS would create an empty file.
    if !db_path.exists() {
        return (0, 0, 0);
    }
    let Ok(conn) = rusqlite::Connection::open_with_flags(
        db_path,
        rusqlite::OpenFlags::SQLITE_OPEN_READ_ONLY | rusqlite::OpenFlags::SQLITE_OPEN_NO_MUTEX,
    ) else {
        return (0, 0, 0);
    };
    let mut pending = 0usize;
    let mut in_progress = 0usize;
    let mut done = 0usize;

    let query = "SELECT status, COUNT(*) FROM todos GROUP BY status";
    let Ok(mut stmt) = conn.prepare(query) else {
        return (0, 0, 0);
    };
    let Ok(rows) = stmt.query_map([], |row| {
        let status: String = row.get(0)?;
        let count: i64 = row.get(1)?;
        Ok((status, count as usize))
    }) else {
        return (0, 0, 0);
    };

    for row in rows.flatten() {
        match row.0.as_str() {
            "pending" => pending = row.1,
            "in_progress" => in_progress = row.1,
            "done" => done = row.1,
            _ => {}
        }
    }

    (pending, in_progress, done)
}

/// Scans `events.jsonl` from newest to oldest and returns the `intent` value
/// from the most recent `report_intent` tool call.
///
/// Tries `toolArgs.intent` first, then `toolResult.sessionLog` as a fallback.
/// Returns `None` if the file is absent, unreadable, or contains no matching entry.
fn load_active_intent(session_dir: &Path) -> Option<String> {
    let text = std::fs::read_to_string(session_dir.join("events.jsonl")).ok()?;
    text.lines()
        .rev()
        .filter(|l| !l.trim().is_empty())
        .find_map(|line| {
            let v: serde_json::Value = serde_json::from_str(line).ok()?;
            if v.get("toolName")?.as_str()? != "report_intent" {
                return None;
            }
            // Prefer toolArgs.intent; fall back to toolResult.sessionLog.
            v.pointer("/toolArgs/intent")
                .or_else(|| v.pointer("/toolResult/sessionLog"))
                .and_then(|val| val.as_str())
                .map(str::to_owned)
        })
}

//! Theme engine — loads opaline themes and maps semantic tokens to ChatTheme.

use opaline::{OpalineColor, ThemeInfo, list_available_themes, load_by_name};
use ratatui_core::style::{Color, Modifier, Style};
use termimad::crossterm::style::Color as CrossColor;
use termimad::{CompoundStyle, MadSkin, StyledChar};

/// Default theme name.
pub const DEFAULT_THEME: &str = "one-dark";

/// Convert an opaline color to ratatui Color.
fn to_color(c: OpalineColor) -> Color {
    Color::Rgb(c.r, c.g, c.b)
}

/// ChatTheme — rendering contract. Views use this, never opaline directly.
#[derive(Clone)]
pub struct ChatTheme {
    pub title_bar: Style,
    pub title_text: Style,
    pub timeline_bg: Style,
    pub body_text: Style,
    pub dim_text: Style,
    pub bold_text: Style,
    pub marker_response: Style,
    pub marker_tool: Style,
    pub marker_bash: Style,
    pub marker_thinking: Style,
    pub marker_warning: Style,
    pub marker_hint: Style,
    pub tool_label: Style,
    pub tool_target: Style,
    pub diff_add: Style,
    pub diff_del: Style,
    pub code_block: Style,
    pub input_prompt: Style,
    pub input_placeholder: Style,
    pub status_bar: Style,
    pub status_right: Style,
    pub picker_title: Style,
    pub picker_item: Style,
    pub picker_selected: Style,
    pub picker_desc: Style,
    pub spinner: Style,
    pub tip_command: Style,
    /// Background color for code blocks.
    pub code_bg: Color,
    /// Background color for overlays (picker backdrop etc.).
    pub backdrop_color: Color,
    /// termimad skin for ratskin markdown rendering.
    pub mad_skin: MadSkin,
}

/// Build `ChatTheme` using the default theme.
pub fn build_theme() -> ChatTheme {
    build_theme_by_name(DEFAULT_THEME)
}

/// Build `ChatTheme` from an opaline theme by name, falling back to Solarized Dark.
pub fn build_theme_by_name(name: &str) -> ChatTheme {
    match load_by_name(name) {
        Some(theme) => map_opaline_theme(&theme),
        None => fallback_theme(),
    }
}

/// List all available theme names for the picker UI.
pub fn available_themes() -> Vec<ThemeInfo> {
    list_available_themes()
}

fn map_opaline_theme(theme: &opaline::Theme) -> ChatTheme {
    let bg_base = to_color(theme.color("bg.base"));
    let bg_panel = to_color(theme.color("bg.panel"));
    let bg_code = to_color(theme.color("bg.code"));
    let text_primary = to_color(theme.color("text.primary"));
    let text_secondary = to_color(theme.color("text.secondary"));
    let text_muted = to_color(theme.color("text.muted"));
    let accent_primary = to_color(theme.color("accent.primary"));
    let accent_secondary = to_color(theme.color("accent.secondary"));
    let accent_tertiary = to_color(theme.color("accent.tertiary"));
    let accent_info = to_color(theme.color("accent.info"));
    let accent_warning = to_color(theme.color("accent.warning"));
    let accent_error = to_color(theme.color("accent.error"));
    let accent_success = to_color(theme.color("accent.success"));
    let code_keyword = to_color(theme.color("code.keyword"));
    let code_string = to_color(theme.color("code.string"));
    let code_function = to_color(theme.color("code.function"));

    let mad_skin = build_mad_skin(
        theme.color("text.primary"),
        theme.color("text.muted"),
        theme.color("accent.info"),
        theme.color("accent.primary"),
        theme.color("text.primary"),
        theme.color("bg.code"),
    );

    ChatTheme {
        title_bar: Style::default().fg(text_secondary).bg(bg_panel),
        title_text: Style::default()
            .fg(accent_primary)
            .add_modifier(Modifier::BOLD),
        timeline_bg: Style::default().fg(text_primary),
        body_text: Style::default().fg(text_primary),
        dim_text: Style::default().fg(text_muted),
        bold_text: Style::default()
            .fg(text_primary)
            .add_modifier(Modifier::BOLD),
        marker_response: Style::default().fg(accent_primary),
        marker_tool: Style::default().fg(accent_success),
        marker_bash: Style::default().fg(accent_secondary),
        marker_thinking: Style::default()
            .fg(accent_tertiary)
            .add_modifier(Modifier::ITALIC),
        marker_warning: Style::default().fg(accent_error),
        marker_hint: Style::default().fg(accent_warning),
        tool_label: Style::default()
            .fg(code_function)
            .add_modifier(Modifier::BOLD),
        tool_target: Style::default().fg(code_string),
        diff_add: Style::default().fg(accent_success),
        diff_del: Style::default().fg(accent_error),
        code_block: Style::default().fg(text_primary),
        input_prompt: Style::default().fg(accent_info),
        input_placeholder: Style::default().fg(text_muted),
        status_bar: Style::default().fg(text_secondary).bg(bg_panel),
        status_right: Style::default().fg(accent_info),
        picker_title: Style::default()
            .fg(accent_primary)
            .add_modifier(Modifier::BOLD),
        picker_item: Style::default().fg(text_primary),
        picker_selected: Style::default()
            .fg(accent_info)
            .add_modifier(Modifier::BOLD),
        picker_desc: Style::default().fg(text_muted),
        spinner: Style::default()
            .fg(accent_warning)
            .add_modifier(Modifier::BOLD),
        tip_command: Style::default().fg(code_keyword),
        code_bg: bg_code,
        backdrop_color: bg_base,
        mad_skin,
    }
}

/// Solarized Dark fallback — used when opaline fails to load a theme.
