pub fn render_to_lines_for_test(app: &mut ChatApp, width: u16, height: u16) -> Vec<String> {
    render_to_lines_for_test_with_users_policy(app, width, height, UsersLayoutPolicy::default())
}

pub fn render_to_lines_for_test_with_users_policy(
    app: &mut ChatApp,
    width: u16,
    height: u16,
    users_policy: UsersLayoutPolicy,
) -> Vec<String> {
    let registry = DefaultRenderRegistry::default();
    render_to_lines_for_test_with_registry(app, width, height, users_policy, &registry)
}

pub fn render_to_lines_for_test_with_registry(
    app: &mut ChatApp,
    width: u16,
    height: u16,
    users_policy: UsersLayoutPolicy,
    registry: &dyn RenderRegistry,
) -> Vec<String> {
    if width == 0 || height == 0 {
        return Vec::new();
    }

    let backend = TestBackend::new(width, height);
    let mut terminal = Terminal::new(backend).expect("test terminal should initialize");

    terminal
        .draw(|frame| render_frame_with_registry(frame, app, 1_200, users_policy, registry))
        .expect("chat frame should render");

    let buffer = terminal.backend().buffer();
    buffer
        .content()
        .chunks(width as usize)
        .map(|row| {
            let mut line = String::new();
            let mut skip = 0;

            for cell in row {
                if skip == 0 {
                    line.push_str(cell.symbol());
                }
                skip = cmp::max(skip, cell.symbol().width()).saturating_sub(1);
            }

            line
        })
        .collect()
}

pub fn render_frame(frame: &mut Frame, app: &mut ChatApp, tick_ms: u64) {
    let registry = DefaultRenderRegistry::default();
    render_frame_with_registry(frame, app, tick_ms, UsersLayoutPolicy::default(), &registry);
}

pub fn render_frame_with_users_policy(
    frame: &mut Frame,
    app: &mut ChatApp,
    tick_ms: u64,
    users_policy: UsersLayoutPolicy,
) {
    let registry = DefaultRenderRegistry::default();
    render_frame_with_registry(frame, app, tick_ms, users_policy, &registry);
}

fn render_frame_with_registry(
    frame: &mut Frame,
    app: &mut ChatApp,
    tick_ms: u64,
    users_policy: UsersLayoutPolicy,
    registry: &dyn RenderRegistry,
) {
    let theme = app.theme().clone();
    let area = frame.area();

    let bg_block = Block::default().style(theme.timeline_bg);
    frame.render_widget(bg_block, area);

    let streaming = app.is_streaming();
    let users_height = users::users_area_height(area.height, users_policy, app);
    let [timeline_area, users_area] = vertical![>=1, ==(users_height)].areas(area);
    let planned_user_slots = users::plan_users_slots(users_area, users_policy, app);
    let mut ctx = RenderCtx::new(app, theme, tick_ms, users_policy);

    render_slot_or_fallback(
        registry,
        RenderSlot::Timeline,
        frame,
        timeline_area,
        &mut ctx,
    );

    if streaming && timeline_area.height > 0 {
        let indicator_area = Rect::new(
            timeline_area.x,
            timeline_area
                .y
                .saturating_add(timeline_area.height.saturating_sub(1)),
            timeline_area.width,
            1,
        );
        streaming::render_streaming_indicator(
            frame,
            indicator_area,
            ctx.tick_ms(),
            ctx.app(),
            ctx.theme(),
        );
    }

    for slot in planned_user_slots {
        render_slot_or_fallback(registry, slot.kind, frame, slot.area, &mut ctx);
    }

    if ctx.app().picker.is_visible() {
        render_slot_or_fallback(registry, RenderSlot::PickerOverlay, frame, area, &mut ctx);
    }
}

fn render_slot_or_fallback(
    registry: &dyn RenderRegistry,
    slot: RenderSlot,
    frame: &mut Frame,
    area: Rect,
    ctx: &mut RenderCtx<'_>,
) {
    if let Err(err) = registry.render_slot(slot, frame, area, ctx) {
        warn!("chat view slot render failed: slot={slot:?} err={err:?}");
        render_slot_error_fallback(frame, area, ctx.theme(), &err);
    }
}

fn render_slot_error_fallback(
    frame: &mut Frame,
    area: Rect,
    theme: &crate::chat::theme::ChatTheme,
    err: &RenderError,
) {
    if area.width == 0 || area.height == 0 {
        return;
    }

    let message = match err {
        RenderError::RegistryMissingSlot(slot) => format!("render slot unavailable: {slot:?}"),
        RenderError::ComponentError(message) => format!("render error: {message}"),
    };
    let fallback = Paragraph::new(Line::from(Span::styled(message, theme.marker_warning)))
        .style(theme.timeline_bg);
    frame.render_widget(fallback, area);
}

pub(in crate::chat::view) fn render_picker_overlay_slot(
    frame: &mut Frame,
    area: Rect,
    ctx: &mut RenderCtx<'_>,
) {
    let theme = ctx.theme().clone();
    picker::render_picker(frame, area, ctx.app_mut(), &theme);
}

use crate::chat::app::ChatApp;
use crate::chat::picker::PICKER_PAGE_SIZE;
use crate::chat::theme::ChatTheme;
use core::cmp;
use ratatui_core::{
    layout::{Constraint, Rect},
    terminal::Frame,
    text::{Line, Span},
};
use ratatui_macros::vertical;
use ratatui_widgets::block::Block;
use ratatui_widgets::borders::BorderType;
use ratatui_widgets::paragraph::Paragraph;
use tui_overlay::{Anchor, Backdrop, Overlay, Slide};
use tui_widget_list::{ListBuilder, ListView};

pub(in crate::chat::view) fn render_picker(
    frame: &mut Frame,
    full_area: Rect,
    app: &mut ChatApp,
    theme: &ChatTheme,
) {
    let filtered_items: Vec<(String, String)> = app
        .picker
        .filtered_items()
        .into_iter()
        .map(|item| (item.label.clone(), item.description.clone()))
        .collect();
    let total = filtered_items.len();
    if full_area.width < 8 || full_area.height < 6 {
        return;
    }

    let visible_count = total.min(PICKER_PAGE_SIZE) as u16;
    // title(1) + visible items + footer(1) + border(2)
    let picker_h = cmp::min(visible_count + 4, full_area.height.saturating_sub(2));
    let picker_w = cmp::min(50, full_area.width.saturating_sub(4));

    let overlay = Overlay::new()
        .anchor(Anchor::BottomLeft)
        .offset(2, -2)
        .width(Constraint::Length(picker_w))
        .height(Constraint::Length(picker_h))
        .slide(Slide::Bottom)
        .backdrop(Backdrop::new(theme.backdrop_color))
        .block(
            Block::bordered()
                .border_type(BorderType::Rounded)
                .border_style(theme.picker_title)
                .title(Line::from(Span::styled(
                    format!(" {} ", app.picker.title),
                    theme.picker_title,
                ))),
        );
    frame.render_stateful_widget(overlay, full_area, app.picker.overlay_state_mut());

    let Some(inner) = app.picker.overlay_state().inner_area() else {
        return;
    };
    if inner.height < 2 || inner.width < 4 || picker_h == 0 || picker_w == 0 {
        return;
    }

    // Reserve last row for footer
    let items_h = inner.height.saturating_sub(1);
    let [items_area, footer_area] = vertical![>=(items_h), ==1].areas(inner);

    let has_up = app.picker.has_scroll_up();
    let has_down = app.picker.has_scroll_down();
    let top_hint = u16::from(has_up);
    let bottom_hint = u16::from(has_down);
    if items_area.height <= top_hint + bottom_hint {
        return;
    }
    let [top_hint_area, list_area, bottom_hint_area] =
        vertical![==(top_hint), >=1, ==(bottom_hint)].areas(items_area);

    if has_up {
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled("  ▲ more", theme.dim_text))),
            top_hint_area,
        );
    }

    if total == 0 {
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled(
                "  No matching commands",
                theme.dim_text,
            ))),
            list_area,
        );
    } else {
        let list_builder = ListBuilder::new(|context| {
            let item = &filtered_items[context.index];
            let marker = if context.is_selected { "› " } else { "  " };
            let label_style = if context.is_selected {
                theme.picker_selected
            } else {
                theme.picker_item
            };

            let mut spans = vec![
                Span::styled(marker, label_style),
                Span::styled(item.0.clone(), label_style),
            ];
            if !item.1.is_empty() {
                spans.push(Span::styled(format!("  {}", item.1), theme.picker_desc));
            }

            (Line::from(spans), 1)
        });
        let list = ListView::new(list_builder, total).scroll_padding(1);
        frame.render_stateful_widget(list, list_area, app.picker.list_state_mut());
    }

    if has_down {
        frame.render_widget(
            Paragraph::new(Line::from(Span::styled("  ▼ more", theme.dim_text))),
            bottom_hint_area,
        );
    }

    // Footer with count info
    let footer_text = format!(
        "↑↓ navigate · enter select · esc cancel  ({}/{})",
        app.picker.selected_index().map_or(0, |index| index + 1),
        total
    );
    let footer = Line::from(Span::styled(footer_text, theme.dim_text));
    frame.render_widget(Paragraph::new(footer), footer_area);
}

//! Contracts for renderable chat view slots.

use crate::chat::app::ChatApp;
use crate::chat::theme::ChatTheme;
use crate::chat::users_state::UsersLayoutPolicy;
use ratatui_core::{layout::Rect, terminal::Frame};

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum RenderSlot {
    Timeline,
    UsersTop,
    UsersInput,
    UsersModel,
    UsersTopInputSeparator,
    UsersInputModelSeparator,
    PickerOverlay,
}

impl RenderSlot {
    pub const fn all_required() -> [RenderSlot; 7] {
        [
            RenderSlot::Timeline,
            RenderSlot::UsersTop,
            RenderSlot::UsersInput,
            RenderSlot::UsersModel,
            RenderSlot::UsersTopInputSeparator,
            RenderSlot::UsersInputModelSeparator,
            RenderSlot::PickerOverlay,
        ]
    }
}

pub struct RenderCtx<'a> {
    app: &'a mut ChatApp,
    theme: ChatTheme,
    tick_ms: u64,
    users_policy: UsersLayoutPolicy,
}

impl<'a> RenderCtx<'a> {
    pub fn new(
        app: &'a mut ChatApp,
        theme: ChatTheme,
        tick_ms: u64,
        users_policy: UsersLayoutPolicy,
    ) -> Self {
        Self {
            app,
            theme,
            tick_ms,
            users_policy,
        }
    }

    pub fn app(&self) -> &ChatApp {
        self.app
    }

    pub fn app_mut(&mut self) -> &mut ChatApp {
        self.app
    }

    pub fn theme(&self) -> &ChatTheme {
        &self.theme
    }

    pub const fn tick_ms(&self) -> u64 {
        self.tick_ms
    }

    pub const fn users_policy(&self) -> UsersLayoutPolicy {
        self.users_policy
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum RenderError {
    RegistryMissingSlot(RenderSlot),
    ComponentError(&'static str),
}

pub trait RenderUnit {
    fn render(
        &self,
        frame: &mut Frame,
        area: Rect,
        ctx: &mut RenderCtx<'_>,
    ) -> Result<(), RenderError>;
}

pub trait RenderRegistry {
    fn resolve(&self, slot: RenderSlot) -> Option<&dyn RenderUnit>;

    fn render_slot(
        &self,
        slot: RenderSlot,
        frame: &mut Frame,
        area: Rect,
        ctx: &mut RenderCtx<'_>,
    ) -> Result<(), RenderError> {
        let unit = self
            .resolve(slot)
            .ok_or(RenderError::RegistryMissingSlot(slot))?;
        unit.render(frame, area, ctx)
    }
}

