const SPARKLE_SPINNER: &[&str] = &["✶", "✸", "✹", "✺", "✹", "✸"];

/// Render a single-line streaming indicator: sparkle spinner + status label.
pub(super) fn render_streaming_indicator(
    frame: &mut Frame,
    area: Rect,
    tick_ms: u64,
    app: &ChatApp,
    theme: &ChatTheme,
) {
    if area.height == 0 || area.width < 4 {
        return;
    }

    let idx = ((tick_ms / 120) % SPARKLE_SPINNER.len() as u64) as usize;
    let sparkle = SPARKLE_SPINNER[idx];

    let label = Line::from(vec![
        Span::styled(format!(" {sparkle} "), theme.spinner),
        Span::styled(app.status_label(), theme.dim_text),
    ]);

    let bar = Paragraph::new(label);
    frame.render_widget(bar, area);
}

/// Markdown segment: either plain text or a fenced code block.
pub(super) enum MdSegment {
    Text(String),
    Code { lang: String, body: String },
}

/// Split markdown into text and fenced-code segments.
/// Unfenced content (including indented code blocks) stays as Text.
pub(super) fn split_code_fences(src: &str) -> Vec<MdSegment> {
    let mut segments = Vec::new();
    let mut text_buf = String::new();
    let mut lines = src.lines().peekable();

    while let Some(line) = lines.next() {
        let trimmed = line.trim();
        if trimmed.starts_with("```") {
            // Flush accumulated text
            if !text_buf.is_empty() {
                segments.push(MdSegment::Text(std::mem::take(&mut text_buf)));
            }
            let lang = trimmed.trim_start_matches('`').trim().to_owned();
            let mut code_buf = String::new();
            let mut closed = false;

            for code_line in lines.by_ref() {
                if code_line.trim().starts_with("```") {
                    closed = true;
                    break;
                }
                if !code_buf.is_empty() {
                    code_buf.push('\n');
                }
                code_buf.push_str(code_line);
            }

            if closed {
                segments.push(MdSegment::Code {
                    lang,
                    body: code_buf,
                });
            } else {
                // Unclosed fence — treat original lines as text
                text_buf.push_str("```");
                text_buf.push_str(&lang);
                text_buf.push('\n');
                text_buf.push_str(&code_buf);
            }
        } else {
            if !text_buf.is_empty() {
                text_buf.push('\n');
            }
            text_buf.push_str(line);
        }
    }

    if !text_buf.is_empty() {
        segments.push(MdSegment::Text(text_buf));
    }

    // Guarantee at least one segment
    if segments.is_empty() {
        segments.push(MdSegment::Text(String::new()));
    }

    segments
}

/// Join soft line-breaks within paragraphs so termimad doesn't treat them as
/// hard breaks.  Preserves structural markdown elements (headings, lists,
/// code fences, tables, blank lines) and code-block interiors.
pub(super) fn normalize_markdown_paragraphs(text: &str) -> String {
    let mut result = String::with_capacity(text.len());
    let lines: Vec<&str> = text.split('\n').collect();
    let mut in_code_block = false;

    for (i, line) in lines.iter().enumerate() {
        let trimmed = line.trim();

        if trimmed.starts_with("```") {
            in_code_block = !in_code_block;
        }

        result.push_str(line);

        if i + 1 < lines.len() {
            if in_code_block {
                result.push('\n');
                continue;
            }
            let next_trimmed = lines[i + 1].trim();
            if is_structural_line(trimmed) || is_structural_line(next_trimmed) {
                result.push('\n');
            } else {
                result.push(' ');
            }
        }
    }
    result
}

fn is_structural_line(s: &str) -> bool {
    s.is_empty()
        || s.starts_with('#')
        || s.starts_with("- ")
        || s.starts_with("* ")
        || s.starts_with("+ ")
        || s.starts_with("```")
        || s.starts_with("> ")
        || s.starts_with('|')
        || s.starts_with("---")
        || s.starts_with("===")
        || s.chars()
            .next()
            .is_some_and(|c| c.is_ascii_digit() && s.contains(". "))
}

use super::*;
use crate::welcome::mascot::render_mascot_lines;
use crate::welcome::state::WelcomeState;
use std::sync::OnceLock;
use std::time::Instant;
use unicode_width::UnicodeWidthStr;

static BANNER_EPOCH: OnceLock<Instant> = OnceLock::new();

/// Render the welcome banner inline in the timeline.
///
/// Layout: colored solid border wrapping [mascot | text] side-by-side.
pub(super) fn render_banner_entry<'a>(
    theme: &ChatTheme,
    _width: u16,
    workspace: &str,
    branch: &str,
) -> Vec<Line<'a>> {
    let version = env!("CARGO_PKG_VERSION");
    let border_style = theme.marker_tool;

    let epoch = BANNER_EPOCH.get_or_init(Instant::now);
    let tick_ms = epoch.elapsed().as_millis() as u64;

    // Build mascot rows (preserve styles)
    let mascot_raw = render_mascot_lines(WelcomeState::new(), tick_ms);
    let mascot_rows: Vec<Vec<Span<'static>>> = mascot_raw
        .into_iter()
        .map(|line| {
            line.spans
                .into_iter()
                .map(|s| Span::styled(s.content.into_owned(), s.style))
                .collect()
        })
        .collect();
    let mascot_height = mascot_rows.len();
    let mascot_width = mascot_rows
        .iter()
        .map(|spans| spans.iter().map(|s| s.content.width()).sum::<usize>())
        .max()
        .unwrap_or(0);

    // Build text rows
    let gap = 2usize;
    let mut text_rows: Vec<Vec<Span<'a>>> = Vec::new();

    // Title
    text_rows.push(vec![
        Span::styled("Blazar", theme.title_text),
        Span::styled(format!(" v{version}"), theme.dim_text),
    ]);

    // Workspace + branch
    if !workspace.is_empty() {
        let mut ctx = vec![Span::styled(workspace.to_owned(), theme.bold_text)];
        if !branch.is_empty() {
            ctx.push(Span::styled(" on ", theme.dim_text));
            ctx.push(Span::styled(format!(" {branch}"), theme.marker_tool));
        }
        text_rows.push(ctx);
    }

    // Prompt
    text_rows.push(vec![Span::styled(
        "Describe a task to get started.",
        theme.body_text,
    )]);

    // Blank separator
    text_rows.push(vec![]);

    // Tips
    text_rows.push(vec![
        Span::styled("Tip: ", theme.dim_text),
        Span::styled("/help", theme.tip_command),
        Span::styled(" for commands, ", theme.dim_text),
        Span::styled("Ctrl+O", theme.tip_command),
        Span::styled(" toggle details.", theme.dim_text),
    ]);
    text_rows.push(vec![Span::styled(
        "Blazar uses AI. Check for mistakes.",
        theme.dim_text,
    )]);

    let content_height = std::cmp::max(mascot_height, text_rows.len());

    // Measure the widest text row
    let text_max_width = text_rows
        .iter()
        .map(|spans| spans.iter().map(|s| s.content.width()).sum::<usize>())
        .max()
        .unwrap_or(0);

    // Inner content: pad(1) + mascot + gap + text + pad(1)
    let inner_width = 1 + mascot_width + gap + text_max_width + 1;

    // Vertically center text within content_height
    let text_y_offset = content_height.saturating_sub(text_rows.len()) / 2;

    // Build combined lines
    let mut lines: Vec<Line<'a>> = Vec::new();

    // Top border: ╭─────╮
    lines.push(Line::from(vec![
        Span::raw(MARGIN),
        Span::styled("╭", border_style),
        Span::styled("─".repeat(inner_width), border_style),
        Span::styled("╮", border_style),
    ]));

    for row_idx in 0..content_height {
        let mut spans: Vec<Span<'a>> = Vec::new();
        spans.push(Span::raw(MARGIN));
        spans.push(Span::styled("│ ", border_style));

        // Mascot column
        if row_idx < mascot_rows.len() {
            let row_spans = &mascot_rows[row_idx];
            let row_w: usize = row_spans.iter().map(|s| s.content.width()).sum();
            for s in row_spans {
                spans.push(Span::styled(s.content.to_string(), s.style));
            }
            if row_w < mascot_width {
                spans.push(Span::raw(" ".repeat(mascot_width - row_w)));
            }
        } else {
            spans.push(Span::raw(" ".repeat(mascot_width)));
        }

        // Gap
        spans.push(Span::raw(" ".repeat(gap)));

        // Text column (pad to text_max_width)
        let text_idx = row_idx.checked_sub(text_y_offset);
        let text_w = if let Some(ti) = text_idx {
            if ti < text_rows.len() {
                let w: usize = text_rows[ti].iter().map(|s| s.content.width()).sum();
                for s in &text_rows[ti] {
                    spans.push(Span::styled(s.content.to_string(), s.style));
                }
                w
            } else {
                0
            }
        } else {
            0
        };
        if text_w < text_max_width {
            spans.push(Span::raw(" ".repeat(text_max_width - text_w)));
        }

        spans.push(Span::styled(" │", border_style));
        lines.push(Line::from(spans));
    }

    // Bottom border: ╰─────╯
    lines.push(Line::from(vec![
        Span::raw(MARGIN),
        Span::styled("╰", border_style),
        Span::styled("─".repeat(inner_width), border_style),
        Span::styled("╯", border_style),
    ]));

    lines
}

