#[derive(Clone, Copy)]
enum MarkdownTextMode {
    NormalizeParagraphs,
    PreserveLines,
}

pub(super) fn render_markdown_block<'a>(
    text: &str,
    theme: &ChatTheme,
    width: u16,
    first_prefix: Vec<Span<'a>>,
    cont_prefix: Vec<Span<'a>>,
) -> Vec<Line<'a>> {
