}

const MAX_PREVIEW_LINES: usize = 2;

pub(crate) fn tool_descriptor(entry: &TimelineEntry) -> Option<EntryDescriptor> {
    let EntryKind::ToolCall {
        tool_name,
        arguments,
        status,
        ..
    } = &entry.kind
    else {
        return None;
    };

    let status_visual = match status {
        ToolCallStatus::Running => StatusVisual::RunningDot,
        ToolCallStatus::Success => StatusVisual::EndedDot,
        ToolCallStatus::Error => StatusVisual::ErrorX,
    };

    let preview_source = preview_source_text(status, entry);
    let subtitle = if arguments.trim().is_empty() {
        extract_tool_subtitle_from_details(tool_name, &entry.details)
    } else {
        let extracted = extract_tool_subtitle(tool_name, arguments);
        if extracted.is_empty() {
            arguments.clone()
        } else {
            extracted
        }
    };

    Some(EntryDescriptor {
        status_visual,
        title: tool_name.clone(),
        subtitle: (!subtitle.is_empty()).then_some(subtitle),
        preview_lines: build_preview_lines(preview_source.as_ref()),
        result_mode: infer_result_mode(tool_name, preview_source.as_ref()),
    })
}

fn preview_source_text<'a>(status: &ToolCallStatus, entry: &'a TimelineEntry) -> Cow<'a, str> {
    if !matches!(status, ToolCallStatus::Running)
        && let Some(full_output) = completed_output_text(&entry.details)
    {
        return Cow::Owned(full_output);
    }

    Cow::Borrowed(&entry.body)
}

fn completed_output_text(details: &str) -> Option<String> {
    tool_call_metadata_line(details)?;

    let content = tool_call_details_payload(details).trim().to_owned();
    (!content.is_empty()).then_some(content)
}

fn build_preview_lines(text: &str) -> Vec<String> {
    text.lines()
        .take(MAX_PREVIEW_LINES)
        .map(ToOwned::to_owned)
        .collect()
}

fn infer_result_mode(tool_name: &str, body: &str) -> ResultMode {
    let is_diff =
        matches!(tool_name, "edit_file") || body.starts_with("diff --git") || body.contains("\n@@");
    if is_diff {
        return ResultMode::Diff;
    }

    if body.contains("```") {
        return ResultMode::Code;
    }

    if body.contains("# ") || body.contains("\n- ") || body.starts_with("- ") {
        return ResultMode::Markdown;
    }

    ResultMode::Plain
}

use super::descriptor::{EntryDescriptor, StatusVisual};
use super::*;
use crate::chat::view::timeline::render_entry::common::tool_badge;

pub(crate) fn status_marker(
    status_visual: StatusVisual,
    theme: &ChatTheme,
) -> (&'static str, Style) {
    match status_visual {
        StatusVisual::RunningDot => ("●", theme.spinner),
        StatusVisual::EndedDot => ("●", theme.diff_add),
        StatusVisual::ErrorX => ("x", theme.marker_warning),
    }
}

pub(super) fn render_tool_descriptor<'a>(
    descriptor: &EntryDescriptor,
    entry: &TimelineEntry,
    theme: &ChatTheme,
    width: u16,
    _marker_style: Style,
) -> Vec<Line<'a>> {
    let mut lines = Vec::new();

    let EntryKind::ToolCall { kind, .. } = &entry.kind else {
        return lines;
    };

    let (status_marker, status_style) = status_marker(descriptor.status_visual, theme);

    let mut header = vec![
        Span::raw(MARGIN),
        Span::styled(format!("{status_marker} "), status_style),
        Span::styled(descriptor.title.clone(), theme.tool_label),
    ];
    if let Some(badge) = tool_badge(*kind) {
        header.push(Span::raw(" "));
        header.push(Span::styled(badge, theme.dim_text));
    }
    lines.push(Line::from(header));

    if let Some(subtitle) = &descriptor.subtitle {
        lines.push(Line::from(vec![
            Span::raw(INDENT),
            Span::styled(subtitle.clone(), theme.tool_target),
        ]));
    }

    let mut preview_text = descriptor.preview_lines.join("\n");
    if preview_text.trim_start().starts_with("```") && preview_text.matches("```").count() % 2 == 1
    {
        preview_text.push_str("\n```");
    }

    let preview = super::super::markdown_body::render_markdown_block_preserve_lines(
        &preview_text,
        theme,
        width,
        vec![Span::raw(INDENT)],
        vec![Span::raw(INDENT)],
    );
    lines.extend(preview);

    lines
}

