//! )?;
//! let _frame = animation.frame_by_index(0).to_ansi_string();
//! # Ok::<(), blazar::welcome::sprite::SpriteError>(())
//! ```

use std::{
    error::Error,
    fmt::{self, Display, Formatter},
    time::{Duration, Instant},
};

use image::{Rgba, RgbaImage};
use ratatui_core::{
    style::{Color, Style},
    text::{Line, Span},
};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Rgb(pub u8, pub u8, pub u8);

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TerminalCell {
    glyph: char,
    fg: Option<Rgb>,
    bg: Option<Rgb>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TerminalFrame {
    rows: Vec<Vec<TerminalCell>>,
}

impl TerminalFrame {
    pub fn to_ansi_string(&self) -> String {
        let mut out = String::new();

        for (row_index, row) in self.rows.iter().enumerate() {
            for cell in row {
                match (cell.fg, cell.bg) {
                    (None, None) => out.push(' '),
                    (fg, bg) => {
                        if let Some(Rgb(r, g, b)) = fg {
                            out.push_str(&format!("\u{1b}[38;2;{r};{g};{b}m"));
                        }
                        if let Some(Rgb(r, g, b)) = bg {
                            out.push_str(&format!("\u{1b}[48;2;{r};{g};{b}m"));
                        }
                        out.push(cell.glyph);
                        out.push_str("\u{1b}[0m");
                    }
                }
            }

            if row_index + 1 != self.rows.len() {
                out.push('\n');
            }
        }

        out
    }

    pub fn to_plain_string(&self) -> String {
        let mut out = String::new();

        for (row_index, row) in self.rows.iter().enumerate() {
            for cell in row {
                out.push(cell.glyph);
            }

            if row_index + 1 != self.rows.len() {
                out.push('\n');
            }
        }

        out
    }

    pub fn to_styled_lines(&self) -> Vec<Line<'static>> {
        self.rows
            .iter()
            .map(|row| {
                let spans = row
                    .iter()
                    .map(|cell| {
                        let mut style = Style::default();
                        if let Some(Rgb(r, g, b)) = cell.fg {
                            style = style.fg(Color::Rgb(r, g, b));
                        }
                        if let Some(Rgb(r, g, b)) = cell.bg {
                            style = style.bg(Color::Rgb(r, g, b));
                        }

                        Span::styled(cell.glyph.to_string(), style)
                    })
                    .collect::<Vec<_>>();

                Line::from(spans)
            })
            .collect()
    }
}

#[allow(dead_code)]
pub struct SpriteAnimation {
    frames: Vec<TerminalFrame>,
    current: usize,
    frame_time: Duration,
    last_tick: Instant,
}

impl SpriteAnimation {
    pub fn from_png_bytes(png: &[u8], frame_count: u32, fps: u16) -> Result<Self, SpriteError> {
        if frame_count == 0 {
            return Err(SpriteError::InvalidFrameCount);
        }
        if fps == 0 {
            return Err(SpriteError::InvalidFps);
        }

        let sheet = image::load_from_memory(png)?.to_rgba8();
        let width = sheet.width();
        let height = sheet.height();

        if width % frame_count != 0 {
            return Err(SpriteError::WidthNotDivisible { width, frame_count });
        }

        let frame_width = width / frame_count;
        let mut frames = Vec::with_capacity(frame_count as usize);

        for frame_index in 0..frame_count {
            let x_offset = frame_index * frame_width;
            frames.push(build_frame(&sheet, x_offset, frame_width, height));
        }

        Ok(Self {
            frames,
            current: 0,
            frame_time: Duration::from_nanos(1_000_000_000 / u64::from(fps)),
            last_tick: Instant::now(),
        })
    }

    pub fn len(&self) -> usize {
        self.frames.len()
    }

    pub fn is_empty(&self) -> bool {
        self.frames.is_empty()
    }

    pub fn frame_by_index(&self, index: usize) -> &TerminalFrame {
        &self.frames[index % self.frames.len()]
    }

    pub fn tick(&mut self) {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_tick);
        let intervals = elapsed.as_nanos() / self.frame_time.as_nanos();

        if intervals > 0 {
            self.current = (self.current + intervals as usize) % self.frames.len();
            let remainder = elapsed.as_nanos() % self.frame_time.as_nanos();
            self.last_tick = now - Duration::from_nanos(remainder as u64);
        }
    }

    pub fn frame(&self) -> &TerminalFrame {
        &self.frames[self.current]
    }
}

#[derive(Debug)]
pub enum SpriteError {
    InvalidFrameCount,
    InvalidFps,
    WidthNotDivisible { width: u32, frame_count: u32 },
    Decode(image::ImageError),
}

impl Display for SpriteError {
    fn fmt(&self, f: &mut Formatter<'_>) -> fmt::Result {
        match self {
            Self::InvalidFrameCount => write!(f, "frame_count must be greater than 0"),
            Self::InvalidFps => write!(f, "fps must be greater than 0"),
            Self::WidthNotDivisible { width, frame_count } => write!(
                f,
                "sprite sheet width {width} is not divisible by frame count {frame_count}"
            ),
            Self::Decode(err) => write!(f, "failed to decode sprite sheet: {err}"),
        }
    }
}

impl Error for SpriteError {
    fn source(&self) -> Option<&(dyn Error + 'static)> {
        match self {
            Self::Decode(err) => Some(err),
            _ => None,
        }
    }
}

impl From<image::ImageError> for SpriteError {
    fn from(value: image::ImageError) -> Self {
        Self::Decode(value)
    }
}

fn build_frame(
    sheet: &RgbaImage,
    x_offset: u32,
    frame_width: u32,
    frame_height: u32,
) -> TerminalFrame {
    let mut rows = Vec::new();
    let mut y = 0;

    while y < frame_height {
        let mut row = Vec::with_capacity(frame_width as usize);

        for x in 0..frame_width {
            let top = *sheet.get_pixel(x_offset + x, y);
            let bottom = if y + 1 < frame_height {
                *sheet.get_pixel(x_offset + x, y + 1)
            } else {
                Rgba([0, 0, 0, 0])
            };

            row.push(pixel_pair_to_cell(top, bottom));
        }

        rows.push(row);
        y += 2;
    }

    TerminalFrame { rows }
}

fn pixel_pair_to_cell(top: Rgba<u8>, bottom: Rgba<u8>) -> TerminalCell {
    let top_visible = top[3] >= 16;
    let bottom_visible = bottom[3] >= 16;

    match (top_visible, bottom_visible) {
        (false, false) => TerminalCell {
            glyph: ' ',
            fg: None,
            bg: None,
        },
        (true, false) => TerminalCell {
            glyph: '▀',
            fg: Some(Rgb(top[0], top[1], top[2])),
            bg: None,
        },
        (false, true) => TerminalCell {
            glyph: '▄',
            fg: Some(Rgb(bottom[0], bottom[1], bottom[2])),
            bg: None,
        },
        (true, true) if top.0[..3] == bottom.0[..3] => TerminalCell {
            glyph: '█',
            fg: Some(Rgb(top[0], top[1], top[2])),
            bg: None,
        },
        (true, true) => TerminalCell {
            glyph: '▀',
            fg: Some(Rgb(top[0], top[1], top[2])),
            bg: Some(Rgb(bottom[0], bottom[1], bottom[2])),
        },
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::time::Duration;

    fn animation_with_frame_time() -> SpriteAnimation {
        SpriteAnimation::from_png_bytes(
            include_bytes!("../../assets/spirit/slime/slime_idle.png"),
            4,
            2,
        )
        .expect("slime idle sprite sheet should decode into frames")
    }

    #[test]
    fn transparent_pair_becomes_space() {
        let cell = pixel_pair_to_cell(Rgba([0, 0, 0, 0]), Rgba([0, 0, 0, 0]));

        assert_eq!(cell.glyph, ' ');
        assert_eq!(cell.fg, None);
        assert_eq!(cell.bg, None);
    }

    #[test]
    fn same_color_pair_becomes_full_block() {
        let cell = pixel_pair_to_cell(Rgba([1, 2, 3, 255]), Rgba([1, 2, 3, 255]));

        assert_eq!(cell.glyph, '█');
        assert_eq!(cell.fg, Some(Rgb(1, 2, 3)));
        assert_eq!(cell.bg, None);
    }

    #[test]
    fn tick_does_not_advance_before_one_interval() {
        let mut animation = animation_with_frame_time();
        let current = animation.current;
        animation.last_tick = Instant::now();

        animation.tick();

        assert_eq!(animation.current, current);
    }

    #[test]
    fn tick_advances_after_one_interval() {
        let mut animation = animation_with_frame_time();
        animation.current = 0;
        animation.last_tick = Instant::now() - animation.frame_time;

        animation.tick();

        assert_eq!(animation.current, 1);
    }

    #[test]
    fn tick_catches_up_over_multiple_intervals() {
        let mut animation = animation_with_frame_time();
        animation.current = 0;
        animation.last_tick =
            Instant::now() - animation.frame_time * 2 - Duration::from_millis(200);

        animation.tick();

        assert_eq!(animation.current, 2);

        let current = animation.current;
        animation.tick();

        assert_eq!(animation.current, current);
    }

    #[test]
    fn tick_wraps_around_frame_sequence() {
        let mut animation = animation_with_frame_time();
        animation.current = animation.len() - 1;
        animation.last_tick = Instant::now() - animation.frame_time;

        animation.tick();

        assert_eq!(animation.current, 0);
    }

    #[test]
    fn high_fps_uses_sub_millisecond_frame_time() {
        let animation = SpriteAnimation::from_png_bytes(
            include_bytes!("../../assets/spirit/slime/slime_idle.png"),
            4,
            2000,
        )
        .expect("slime idle sprite sheet should decode into frames");

        assert_eq!(animation.frame_time, Duration::from_nanos(500_000));
        assert!(animation.frame_time > Duration::ZERO);
    }
}

use std::io::{self, BufRead, Write};
use std::thread;
use std::time::Duration;

use crate::welcome::state::WelcomeState;
use crate::welcome::view::render_scene;

const IDLE_AFTER_MS: u64 = 1_200;
const ANIMATION_SAMPLE_MS: u64 = 125;

pub struct WelcomeController {
    state: WelcomeState,
}

impl WelcomeController {
    pub fn new() -> Self {
        Self {
            state: WelcomeState::new(),
        }
    }

    pub fn frame(&mut self, now_ms: u64, input: &str) -> String {
        self.state = self.state.tick(now_ms, !input.trim().is_empty());
        render_scene(self.state, now_ms)
    }
}

pub fn run_session<R: BufRead, W: Write>(input: &mut R, output: &mut W) -> io::Result<()> {
    let mut welcome = WelcomeController::new();
    writeln!(output, "{}", welcome.frame(0, ""))?;

    thread::sleep(Duration::from_millis(IDLE_AFTER_MS));
    writeln!(output, "{}", welcome.frame(IDLE_AFTER_MS, ""))?;

    thread::sleep(Duration::from_millis(ANIMATION_SAMPLE_MS));
    writeln!(
        output,
        "{}",
        welcome.frame(IDLE_AFTER_MS + ANIMATION_SAMPLE_MS, "")
    )?;

    let mut line = String::new();
    input.read_line(&mut line)?;

    if !line.trim().is_empty() {
        writeln!(
            output,
            "{}",
            welcome.frame(IDLE_AFTER_MS + ANIMATION_SAMPLE_MS, &line)
        )?;
    }

    Ok(())
}

pub fn run_preview<W: Write>(output: &mut W) -> io::Result<()> {
    let mut welcome = WelcomeController::new();
    writeln!(output, "{}", welcome.frame(0, ""))?;
    writeln!(output, "{}", welcome.frame(IDLE_AFTER_MS, ""))?;
    writeln!(
        output,
        "{}",
        welcome.frame(IDLE_AFTER_MS + ANIMATION_SAMPLE_MS, "")
    )?;
    Ok(())
}

impl Default for WelcomeController {
    fn default() -> Self {
        Self::new()
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum PresenceMode {
    Greeting,
    IdleSparkle,
    Listening,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct WelcomeState {
    mode: PresenceMode,
    mode_entered_at_ms: u64,
    last_activity_at_ms: u64,
}

impl WelcomeState {
    pub fn new() -> Self {
        Self {
            mode: PresenceMode::Greeting,
            mode_entered_at_ms: 0,
            last_activity_at_ms: 0,
        }
    }

    pub fn mode(&self) -> PresenceMode {
        self.mode
    }

    pub fn tick(self, now_ms: u64, has_input: bool) -> Self {
        let mode_elapsed = now_ms.saturating_sub(self.mode_entered_at_ms);
        let activity_elapsed = now_ms.saturating_sub(self.last_activity_at_ms);

        match (self.mode, has_input) {
            (_, true) if self.mode != PresenceMode::Listening => Self {
                mode: PresenceMode::Listening,
                mode_entered_at_ms: now_ms,
                last_activity_at_ms: now_ms,
            },
            (PresenceMode::Listening, true) => Self {
                mode: PresenceMode::Listening,
                mode_entered_at_ms: self.mode_entered_at_ms,
                last_activity_at_ms: now_ms,
            },
            (PresenceMode::Greeting, false) if mode_elapsed >= 1_200 => Self {
                mode: PresenceMode::IdleSparkle,
                mode_entered_at_ms: now_ms,
                last_activity_at_ms: now_ms,
            },
            (PresenceMode::Listening, false) if activity_elapsed >= 1_500 => Self {
                mode: PresenceMode::IdleSparkle,
                mode_entered_at_ms: now_ms,
                last_activity_at_ms: now_ms,
            },
            _ => self,
        }
    }

    pub fn animation_frame_index(
        self,
        now_ms: u64,
        frame_count: usize,
        frame_interval_ms: u64,
    ) -> usize {
        let elapsed = now_ms.saturating_sub(self.mode_entered_at_ms);
        ((elapsed / frame_interval_ms) as usize) % frame_count
    }
}

impl Default for WelcomeState {
    fn default() -> Self {
        Self::new()
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct MascotPalette {
    pub coat_ansi: &'static str,
    pub pink_ansi: &'static str,
    pub mint_ansi: &'static str,
    pub blue_ansi: &'static str,
    pub horn_ansi: &'static str,
    pub star_ansi: &'static str,
    pub reset_ansi: &'static str,
}

pub const MASCOT_NAME: &str = "Star Sugar Guidepony";
pub const MASCOT_ALIAS_ZH: &str = "星糖导航马";

pub const MASCOT_PALETTE: MascotPalette = MascotPalette {
    coat_ansi: "\u{1b}[38;5;230m",
    pink_ansi: "\u{1b}[38;5;218m",
    mint_ansi: "\u{1b}[38;5;159m",
    blue_ansi: "\u{1b}[38;5;153m",
    horn_ansi: "\u{1b}[38;5;223m",
    star_ansi: "\u{1b}[38;5;222m",
    reset_ansi: "\u{1b}[0m",
};

pub fn paint(text: &str, ansi: &str) -> String {
    format!("{}{}{}", ansi, text, MASCOT_PALETTE.reset_ansi)
}

use crate::welcome::mascot::render_mascot;
use crate::welcome::state::{PresenceMode, WelcomeState};
use crate::welcome::theme::{MASCOT_ALIAS_ZH, MASCOT_NAME, MASCOT_PALETTE, paint};

pub fn render_scene(state: WelcomeState, now_ms: u64) -> String {
    let left = render_mascot(state, now_ms)
        .lines()
        .map(str::to_owned)
        .collect::<Vec<_>>();
    let left_raw_width = left
        .iter()
        .map(|line| strip_ansi(line).chars().count())
        .max()
        .unwrap_or(0);

    let right = vec![
        paint("BLAZAR", MASCOT_PALETTE.blue_ansi),
        format!("{MASCOT_NAME} / {MASCOT_ALIAS_ZH}"),
        status_copy(state.mode()).to_string(),
        String::new(),
        "Describe a task to begin".to_string(),
        "> ".to_string(),
    ];

    join_columns(&left, left_raw_width + 4, &right)
}

fn status_copy(mode: PresenceMode) -> &'static str {
    match mode {
        PresenceMode::Greeting => "A rainbow helper just spotted you",
        PresenceMode::IdleSparkle => "Waiting with a sprinkle of stardust",
        PresenceMode::Listening => "Listening with twinkly focus",
    }
}

fn join_columns(left: &[String], left_width: usize, right: &[String]) -> String {
    let rows = left.len().max(right.len());
    let mut lines = Vec::with_capacity(rows);

    for index in 0..rows {
        let left_line = left.get(index).map(String::as_str).unwrap_or("");
        let right_line = right.get(index).map(String::as_str).unwrap_or("");
        let left_visible_width = strip_ansi(left_line).chars().count();
        let padding = " ".repeat(left_width.saturating_sub(left_visible_width));
        lines.push(format!("{left_line}{padding}{right_line}"));
    }

    lines.join("\n")
}

fn strip_ansi(line: &str) -> String {
    let mut out = String::new();
    let mut chars = line.chars().peekable();

    while let Some(ch) = chars.next() {
        if ch == '\u{1b}' && chars.next_if_eq(&'[').is_some() {
            for next in chars.by_ref() {
                if next == 'm' {
                    break;
                }
            }
        } else {
            out.push(ch);
        }
    }

    out
}
